mplexity.. Risk is medium; keep edits narrow.\",\"inspections\":{\"reads\":[{\"path\":\"core/project-memory.ts\",\"content\":\"/**\\n * ProjectMemory — persistent per-repo knowledge across Aedis sessions.\\n *\\n * Stored at {projectRoot}/.aedis/memory.json. Tracks:\\n *   - last 20 file paths touched (deduped, most-recent-first)\\n *   - last 10 task summaries (prompt, verdict, commitSha, cost, timestamp)\\n *   - up to 20 file clusters that tend to change together\\n *   - repo language inferred from tsconfig.json / package.json presence\\n *\\n * The store is intentionally tiny and self-contained: no schemas, no DB,\\n * no external state. A missing or malformed file is treated as \\\"no memory\\n * yet\\\" rather than an error so the rest of the pipeline can keep running.\\n */\\n\\nimport { access, mkdir, readFile, rename, unlink, writeFile } from \\\"node:fs/promises\\\";\\nimport { withRepoLock } from \\\"./file-lock.js\\\";\\nimport { dirname, join, resolve } from \\\"node:path\\\";\\n\\n// ─── Public types ────────────────────────────────────────────────────\\n\\nexport interface TaskSummary {\\n  readonly prompt: string;\\n  readonly verdict: string;\\n  readonly commitSha: string | null;\\n  readonly cost: number;\\n  readonly timestamp: string;\\n  readonly normalizedPrompt?: string;\\n  readonly scopeType?: string;\\n  readonly complexityTier?: string;\\n  readonly resultSummary?: string;\\n  readonly verificationVerdict?: string;\\n  readonly failureSummary?: string;\\n  readonly successPattern?: string;\\n  readonly affectedSystems?: readonly string[];\\n  readonly changeTypes?: readonly string[];\\n  /**\\n   * Optional list of files touched by this task. When provided, recordTask\\n   * folds them into the memory's `recentFiles` list (deduped, capped).\\n   */\\n  readonly filesTouched?: readonly string[];\\n  readonly taskTypeKey?: string;\\n  readonly plannedFilesCount?: number;\\n  readonly missingFiles?: readonly string[];\\n  readonly undeclaredFiles?: readonly string[];\\n  readonly verificationCoverageRatio?: number | null;\\n  readonly validatedRatio?: number | null;\\n  // ─── Evaluation feedback ────────────────────────────────────────\\n  /** Aedis confidence at time of run (0-1). */\\n  readonly aedisConfidence?: number | null;\\n  /** Crucibulum evaluation score (0-100), null if not evaluated. */\\n  readonly evaluationScore?: number | null;\\n  /** Whether the evaluation passed. */\\n  readonly evaluationPassed?: boolean | null;\\n  /** Direction of disagreement between Aedis confidence and evaluation. */\\n  readonly disagreementDirection?: \\\"aligned\\\" | \\\"aedis-overconfident\\\" | \\\"aedis-underconfident\\\" | null;\\n}\\n\\nexport interface FileCluster {\\n  readonly files: string[];\\n  readonly changedTogether: number;\\n  readonly lastSeen: string;\\n}\\n\\nexport interface ProjectMemory {\\n  readonly projectRoot: string;\\n  readonly language: string;\\n  readonly recentFiles: readonly string[];\\n  readonly recentTasks: readonly TaskSummary[];\\n  readonly fileClusters: readonly FileCluster[];\\n  readonly taskPatterns: readonly TaskPatternProfile[];\\n  readonly updatedAt: string;\\n  readonly schemaVersion: number;\\n}\\n\\nexport interface TaskPatternProfile {\\n  readonly taskTypeKey: string;\\n  readonly observedRuns: number;\\n  readonly avgFilesChanged: number;\\n  readonly successRate: number;\\n  readonly verificationGapRate: number;\\n  readonly commonFailureReasons: readonly string[];\\n  readonly commonMissingFiles: readonly string[];\\n  readonly lastSeen: string;\\n  // ─── Trust calibration (derived from evaluation feedback) ──────\\n  /** Number of runs that had Crucibulum evaluations. */\\n  readonly evaluatedRuns: number;\\n  /** Average Crucibulum score for evaluated runs (0-100). */\\n  readonly avgEvaluationScore: number;\\n  /** Rate of overconfidence: high Aedis confidence + failed evaluation. */\\n  readonly overconfidenceRate: number;\\n  /**\\n   * Confidence dampening factor derived from historical accuracy.\\n   * Applied as a multiplier (0.8-1.0) to confidence for this task type.\\n   * 1.0 = no dampening, 0.8 = maximum dampening for repeatedly\\n   * overconfident patterns. Only meaningful when evaluatedRuns >= 3.\\n   */\\n  readonly confidenceDampening: number;\\n  /**\\n   * Reliability tier for this task archetype.\\n   *   \\\"reliable\\\"  — successRate >= 0.8, overconfidenceRate < 0.15\\n   *   \\\"risky\\\"     — successRate < 0.6 OR overconfidenceRate >= 0.3\\n   *   \\\"caution\\\"   — everything else\\n   *   \\\"unknown\\\"   — fewer than 3 observed runs\\n   */\\n  readonly reliabilityTier: \\\"reliable\\\" | \\\"risky\\\" | \\\"caution\\\" | \\\"unknown\\\";\\n}\\n\\n// ─── Internals ───────────────────────────────────────────────────────\\n\\nconst MEMORY_DIR = \\\".aedis\\\";\\nconst MEMORY_FILE = \\\"memory.json\\\";\\nconst MAX_FILES = 20;\\nconst MAX_TASKS = 10;\\nconst MAX_CLUSTERS = 20;\\nconst MAX_PATTERNS = 20;\\nconst MAX_PATTERN_LIST = 5;\\n\\nfunction memoryPath(projectRoot: string): string {\\n  return join(resolve(projectRoot), MEMORY_DIR, MEMORY_FILE);\\n}\\n\\nasync function fileExists(path: string): Promise<boolean> {\\n  try {\\n    await access(path);\\n    return true;\\n  } catch {\\n    return false;\\n  }\\n}\\n\\nasync function detectLanguage(projectRoot: string): Promise<string> {\\n  const root = resolve(projectRoot);\\n  if (await fileExists(join(root, \\\"tsconfig.json\\\"))) return \\\"typescript\\\";\\n  if (await fileExists(join(root, \\\"Cargo.toml\\\"))) return \\\"rust\\\";\\n  if (await fileExists(join(root, \\\"go.mod\\\"))) return \\\"go\\\";\\n  if (\\n    await fileExists(join(root, \\\"requirements.txt\\\")) ||\\n    await fileExists(join(root, \\\"pyproject.toml\\\"))\\n  ) return \\\"python\\\";\\n  if (await fileExists(join(root, \\\"pom.xml\\\"))) return \\\"java\\\";\\n  if (await fileExists(join(root, \\\"package.json\\\"))) return \\\"javascript\\\";\\n  return \\\"unknown\\\";\\n}\\n\\nfunction emptyMemory(projectRoot: string, language: string): ProjectMemory {\\n  return {\\n    projectRoot: resolve(projectRoot),\\n    language,\\n    recentFiles: [],\\n    recentTasks: [],\\n    fileClusters: [],\\n    taskPatterns: [],\\n    updatedAt: new Date().toISOString(),\\n    schemaVersion: 1,\\n  };\\n}\\n\\nfunction isTaskSummary(value: unknown): value is TaskSummary {\\n  if (!value || typeof value !== \\\"object\\\") return false;\\n  const v = value as Record<string, unknown>;\\n  return (\\n    typeof v.prompt === \\\"string\\\" &&\\n    typeof v.verdict === \\\"string\\\" &&\\n    typeof v.timestamp === \\\"string\\\" &&\\n    typeof v.cost === \\\"number\\\" &&\\n    (v.commitSha === null || typeof v.commitSha === \\\"string\\\")\\n  );\\n}\\n\\nfunction isFileCluster(value: unknown): value is FileCluster {\\n  if (!value || typeof value !== \\\"object\\\") return false;\\n  const v = value as Record<string, unknown>;\\n  return (\\n    Array.isArray(v.files) &&\\n    v.files.every((entry) => typeof entry === \\\"string\\\") &&\\n    typeof v.changedTogether === \\\"number\\\" &&\\n    typeof v.lastSeen === \\\"string\\\"\\n  );\\n}\\n\\nfunction normalizeTouchedFiles(files: readonly string[]): string[] {\\n  return Array.from(\\n    new Set(\\n      files.filter((file): file is string => typeof file === \\\"string\\\" && file.length > 0),\\n    ),\\n  );\\n}\\n\\nfunction isTaskPatternProfile(value: unknown): value is TaskPatternProfile {\\n  if (!value || typeof value !== \\\"object\\\") return false;\\n  const v = value as Record<string, unknown>;\\n  if (!(\\n    typeof v.taskTypeKey === \\\"string\\\" &&\\n    typeof v.observedRuns === \\\"number\\\" &&\\n    typeof v.avgFilesChanged === \\\"number\\\" &&\\n    typeof v.successRate === \\\"number\\\" &&\\n    typeof v.verificationGapRate === \\\"number\\\" &&\\n    Array.isArray(v.commonFailureReasons) &&\\n    Array.isArray(v.commonMissingFiles) &&\\n    typeof v.lastSeen === \\\"string\\\"\\n  )) return false;\\n  // Backfill trust calibration fields for older memory entries\\n  if (typeof v.evaluatedRuns !== \\\"number\\\") (v as any).evaluatedRuns = 0;\\n  if (typeof v.avgEvaluationScore !== \\\"number\\\") (v as any).avgEvaluationScore = 0;\\n  if (typeof v.overconfidenceRate !== \\\"number\\\") (v as any).overconfidenceRate = 0;\\n  if (typeof v.confidenceDampening !== \\\"number\\\") (v as any).confidenceDampening = 1.0;\\n  if (typeof v.reliabilityTier !== \\\"string\\\") (v as any).reliabilityTier = \\\"unknown\\\";\\n  return true;\\n}\\n\\nfunction normalizeList(values: readonly string[], max = MAX_PATTERN_LIST): string[] {\\n  const counts = new Map<string, number>();\\n  for (const value of values) {\\n    const trimmed = value.trim();\\n    if (!trimmed) continue;\\n    counts.set(trimmed, (counts.get(trimmed) ?? 0) + 1);\\n  }\\n  return [...counts.entries()]\\n    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))\\n    .slice(0, max)\\n    .map(([value]) => value);\\n}\\n\\nexport function deriveTaskTypeKey(prompt: string, scopeType?: string): string {\\n  const normalized = prompt.toLowerCase();\\n  let action = \\\"change\\\";\\n  if (/\\\\b(refactor|rename)\\\\b/.test(normalized)) {\\n    action = \\\"refactor\\\";\\n  } else if (/\\\\b(migrate|migration|schema)\\\\b/.test(normalized)) {\\n    action = \\\"migration\\\";\\n  } else if (/\\\\b(fix|bug|repair|correct)\\\\b/.test(normalized)) {\\n    action = \\\"fix\\\";\\n  } else if (/\\\\b(add|build|create|implement)\\\\b/.test(normalized)) {\\n    action = \\\"build\\\";\\n  } else if (/\\\\b(test|spec)\\\\b/.test(normalized)) {\\n    action = \\\"tests\\\";\\n  }\\n  return `${scopeType ?? \\\"unknown\\\"}:${action}`;\\n}\\n\\nfunction computeReliabilityTier(\\n  observedRuns: number,\\n  successRate: number,\\n  overconfidenceRate: number,\\n): TaskPatternProfile[\\\"reliabilityTier\\\"] {\\n  if (observedRuns < 3) return \\\"unknown\\\";\\n  if (successRate >= 0.8 && overconfidenceRate < 0.15) return \\\"reliable\\\";\\n  if (successRate < 0.6 || overconfidenceRate >= 0.3) return \\\"risky\\\";\\n  return \\\"caution\\\";\\n}\\n\\nfunction computeConfidenceDampening(\\n  evaluatedRuns: number,\\n  overconfidenceRate: number,\\n): number {\\n  // Only dampen when we have enough evaluation data (3+ evaluated runs)\\n  if (evaluatedRuns < 3) return 1.0;\\n  // Linear dampening: max 20% reduction for 100% overconfidence rate\\n  // Clamped to [0.80, 1.00] for stability — never crush confidence entirely\\n  return Math.max(0.80, 1.0 - overconfidenceRate * 0.20);\\n}\\n\\nfunction updateTaskPatterns(\\n  patterns: readonly TaskPatternProfile[],\\n  summary: TaskSummary,\\n  touchedFiles: readonly string[],\\n): TaskPatternProfile[] {\\n  const taskTypeKey = summary.taskTypeKey ?? deriveTaskTypeKey(summary.prompt, summary.scopeType);\\n  const filesChanged = touchedFiles.length;\\n  const success = summary.verdict === \\\"success\\\" ? 1 : 0;\\n  const verificationGap = typeof summary.verificationCoverageRatio === \\\"number\\\" && summary.verificationCoverageRatio < 1 ? 1 : 0;\\n  const failureReasons = summary.failureSummary ? [summary.failureSummary] : [];\\n  const missingFiles = [\\n    ...(summary.missingFiles ?? []),\\n    ...(summary.undeclaredFiles ?? []).map((file) => `undeclared:${file}`),\\n  ];\\n\\n  // Evaluation feedback signals\\n  const hasEvaluation = typeof summary.evaluationScore === \\\"number\\\";\\n  const evaluationContribution = hasEvaluation ? 1 : 0;\\n  const evaluationScoreContribution = typeof summary.evaluationScore === \\\"number\\\" ? summary.evaluationScore : 0;\\n  // Overconfident = Aedis confidence >= 0.7 AND evaluation failed\\n  const isOverconfident = (\\n    hasEvaluation &&\\n    summary.evaluationPassed === false &&\\n    typeof summary.aedisConfidence === \\\"number\\\" &&\\n    summary.aedisConfidence >= 0.7\\n  ) ? 1 : 0;\\n\\n  const next = [...patterns];\\n  const idx = next.findIndex((pattern) => pattern.taskTypeKey === taskTypeKey);\\n  if (idx < 0) {\\n    const overconfidenceRate = isOverconfident;\\n    const evaluatedRuns = evaluationContribution;\\n    next.unshift({\\n      taskTypeKey,\\n      observedRuns: 1,\\n      avgFilesChanged: filesChanged,\\n      successRate: success,\\n      verificationGapRate: verificationGap,\\n      commonFailureReasons: normalizeList(failureReasons),\\n      commonMissingFiles: normalizeList(missingFiles),\\n      lastSeen: summary.timestamp,\\n      evaluatedRuns,\\n      avgEvaluationScore: evaluationScoreContribution,\\n      overconfidenceRate,\\n      confidenceDampening: computeConfidenceDampening(evaluatedRuns, overconfidenceRate),\\n      reliabilityTier: computeReliabilityTier(1, success, overconfidenceRate),\\n    });\\n  } else {\\n    const prev = next[idx];\\n    const observedRuns = prev.observedRuns + 1;\\n    const evaluatedRuns = prev.evaluatedRuns + evaluationContribution;\\n    const avgEvaluationScore = evaluatedRuns > 0\\n      ? Number((((prev.avgEvaluationScore * prev.evaluatedRuns) + evaluationScoreContribution) / evaluatedRuns).toFixed(1))\\n      : 0;\\n    const overconfidenceRate = evaluatedRuns > 0\\n      ? Number((((prev.overconfidenceRate * prev.evaluatedRuns) + isOverconfident) / evaluatedRuns).toFixed(3))\\n      : 0;\\n    const successRate = Number((((prev.successRate * prev.observedRuns) + success) / observedRuns).toFixed(3));\\n\\n    next[idx] = {\\n      taskTypeKey,\\n      observedRuns,\\n      avgFilesChanged: Number((((prev.avgFilesChanged * prev.observedRuns) + filesChanged) / observedRuns).toFixed(2)),\\n      successRate,\\n      verificationGapRate: Number((((prev.verificationGapRate * prev.observedRuns) + verificationGap) / observedRuns).toFixed(3)),\\n      commonFailureReasons: normalizeList([...prev.commonFailureReasons, ...failureReasons]),\\n      commonMissingFiles: normalizeList([...prev.commonMissingFiles, ...missingFiles]),\\n      lastSeen: summary.timestamp,\\n      evaluatedRuns,\\n      avgEvaluationScore,\\n      overconfidenceRate,\\n      confidenceDampening: computeConfidenceDampening(evaluatedRuns, overconfidenceRate),\\n      reliabilityTier: computeReliabilityTier(observedRuns, successRate, overconfidenceRate),\\n    };\\n  }\\n\\n  // Decay: patterns not seen in 30+ days lose half their weight per\\n  // save cycle. This prevents stale historical data from permanently\\n  // influencing confidence calibration. The decay is gentle — a\\n  // pattern needs to be unseen for multiple months to fully evaporate.\\n  const DECAY_AGE_MS = 30 * 24 * 60 * 60 * 1000; // 30 days\\n  const now = Date.now();\\n  for (let i = 0; i < next.length; i++) {\\n    const age = now - new Date(next[i].lastSeen).getTime();\\n    if (age > DECAY_AGE_MS && next[i].observedRuns > 1) {\\n      const p = next[i];\\n      // Halve observed runs to reduce weight, but never below 1\\n      const decayedRuns = Math.max(1, Math.floor(p.observedRuns / 2));\\n      next[i] = { ...p, observedRuns: decayedRuns };\\n    }\\n  }\\n\\n  return next\\n    .sort((a, b) => b.observedRuns - a.observedRuns || b.lastSeen.localeCompare(a.lastSeen))\\n    .slice(0, MAX_PATTERNS);\\n}\\n\\nexport function findPatternWarnings(\\n  memory: ProjectMemory,\\n  input: {\\n    prompt: string;\\n    scopeType?: string;\\n    plannedFilesCount?: number;\\n  },\\n): string[] {\\n  const taskTypeKey = deriveTaskTypeKey(input.prompt, input.scopeType);\\n  const pattern = memory.taskPatterns.find((entry) => entry.taskTypeKey === taskTypeKey);\\n  if (!pattern || pattern.observedRuns < 2) return [];\\n\\n  const warnings: string[] = [];\\n  if (\\n    typeof input.plannedFilesCount === \\\"number\\\" &&\\n    pattern.avgFilesChanged >= input.plannedFilesCount + 1.5\\n  ) {\\n    warnings.push(\\n      `Similar ${taskTypeKey} tasks usually touch about ${Math.round(pattern.avgFilesChanged)} files; current plan may be too narrow.`,\\n    );\\n  }\\n  if (pattern.verificationGapRate >= 0.4) {\\n    warnings.push(\\n      `Similar ${taskTypeKey} tasks often ship with verification gaps (${Math.round(pattern.verificationGapRate * 100)}%). Review coverage closely.`,\\n    );\\n  }\\n  if (pattern.commonFailureReasons.length > 0 && pattern.successRate < 0.7) {\\n    warnings.push(\\n      `Similar ${taskTypeKey} tasks fail often (${Math.round(pattern.successRate * 100)}% success). Common issue: ${pattern.commonFailureReasons[0]}.`,\\n    );\\n  }\\n  if (pattern.commonMissingFiles.length > 0) {\\n    warnings.push(\\n      `Similar ${taskTypeKey} tasks commonly miss: ${pattern.commonMissingFiles.slice(0, 2).join(\\\", \\\")}.`,\\n    );\\n  }\\n  return warnings.slice(0, 3);\\n}\\n\\n// ─── Trust calibration queries ──────────────────────────────────────\\n\\nexport interface HistoricalInsight {\\n  /** One-line description for the explanation layer. */\\n  readonly line: string;\\n  /** Machine-readable category for UI filtering. */\\n  readonly category: \\\"success-rate\\\" | \\\"overconfidence\\\" | \\\"verification-gap\\\" | \\\"reliability\\\";\\n  /** Severity: determines whether this displaces other explanation lines. */\\n  readonly severity: \\\"info\\\" | \\\"warning\\\";\\n}\\n\\n/**\\n * Generate historical insights for a task pattern. Returns 0-2 compact\\n * lines suitable for the explanation layer. Only produces insights when\\n * there's enough history (3+ runs) to be meaningful.\\n */\\nexport function findHistoricalInsights(\\n  memory: ProjectMemory,\\n  input: { prompt: string; scopeType?: string },\\n): readonly HistoricalInsight[] {\\n  const taskTypeKey = deriveTaskTypeKey(input.prompt, input.scopeType);\\n  const pattern = memory.taskPatterns.find((p) => p.taskTypeKey === taskTypeKey);\\n  if (!pattern || pattern.observedRuns < 3) return [];\\n\\n  const insights: HistoricalInsight[] = [];\\n\\n  // Success rate insight — always show if enough history\\n  const pct = Math.round(pattern.successRate * 100);\\n  insights.push({\\n    line: `Similar changes: ${pct}% success rate across ${pattern.observedRuns} runs`,\\n    category: \\\"success-rate\\\",\\n    severity: \\\"info\\\",\\n  });\\n\\n  // Overconfidence warning — only when evaluated and drift detected\\n  if (pattern.evaluatedRuns >= 3 && pattern.overconfidenceRate >= 0.25) {\\n    insights.push({\\n      line: `Aedis confidence previously overstated for this pattern (${Math.round(pattern.overconfidenceRate * 100)}% overconfident)`,\\n      category: \\\"overconfidence\\\",\\n      severity: \\\"warning\\\",\\n    });\\n  }\\n\\n  // Reliability tier context\\n  if (pattern.reliabilityTier === \\\"risky\\\") {\\n    insights.push({\\n      line: `This task type is historically risky — consider decomposition or stronger review`,\\n      category: \\\"reliability\\\",\\n      severity: \\\"warning\\\",\\n    });\\n  }\\n\\n  return insights.slice(0, 2);\\n}\\n\\n/**\\n * Get the confidence dampening factor for a task pattern. Returns 1.0\\n * (no dampening) when there's insufficient history or the pattern is\\n * reliable. Returns < 1.0 when the pattern is historically overconfident.\\n */\\nexport function getConfidenceDampening(\\n  memory: ProjectMemory,\\n  input: { prompt: string; scopeType?: string },\\n): number {\\n  const taskTypeKey = deriveTaskTypeKey(input.prompt, input.scopeType);\\n  const pattern = memory.taskPatterns.find((p) => p.taskTypeKey === taskTypeKey);\\n  if (!pattern) return 1.0;\\n  return pattern.confidenceDampening;\\n}\\n\\n/**\\n * Recommend whether strict mode should be enabled based on historical\\n * pattern data. Returns true when the pattern shows frequent verification\\n * gaps or low reliability.\\n */\\nexport function shouldRecommendStrictMode(\\n  memory: ProjectMemory,\\n  input: { prompt: string; scopeType?: string },\\n): boolean {\\n  const taskTypeKey = deriveTaskTypeKey(input.prompt, input.scopeType);\\n  const pattern = memory.taskPatterns.find((p) => p.taskTypeKey === taskTypeKey);\\n  if (!pattern || pattern.observedRuns < 3) return false;\\n  // Recommend strict mode when verification gaps are frequent\\n  // or the pattern is historically risky\\n  return pattern.verificationGapRate >= 0.5 || pattern.reliabilityTier === \\\"risky\\\";\\n}\\n\\n/**\\n * Get the historical reliability tier for a task pattern.\\n * Returns null when no pattern matches.\\n */\\nexport function getReliabilityTier(\\n  memory: ProjectMemory,\\n  input: { prompt: string; scopeType?: string },\\n): TaskPatternProfile[\\\"reliabilityTier\\\"] | null {\\n  const taskTypeKey = deriveTaskTypeKey(input.prompt, input.scopeType);\\n  const pattern = memory.taskPatterns.find((p) => p.taskTypeKey === taskTypeKey);\\n  if (!pattern) return null;\\n  return pattern.reliabilityTier;\\n}\\n\\nfunction updateFileClusters(\\n  clusters: readonly FileCluster[],\\n  touchedFiles: readonly string[],\\n  timestamp: string,\\n): FileCluster[] {\\n  if (touchedFiles.length <= 1) {\\n    return [...clusters].slice(0, MAX_CLUSTERS);\\n  }\\n\\n  const normalizedTouched = normalizeTouchedFiles(touchedFiles).sort();\\n  const existingIndex = clusters.findIndex((cluster) =>\\n    cluster.files.some((file) => normalizedTouched.includes(file)),\\n  );\\n\\n  const nextClusters = [...clusters];\\n\\n  if (existingIndex >= 0) {\\n    const existing = nextClusters[existingIndex];\\n    const mergedFiles = Array.from(new Set([...existing.files, ...normalizedTouched])).sort();\\n    nextClusters[existingIndex] = {\\n      files: mergedFiles,\\n      changedTogether: existing.changedTogether + 1,\\n      lastSeen: timestamp,\\n    };\\n  } else {\\n    nextClusters.unshift({\\n      files: normalizedTouched,\\n      changedTogether: 1,\\n      lastSeen: timestamp,\\n    });\\n  }\\n\\n  return nextClusters\\n    .sort((a, b) => {\\n      if (b.changedTogether !== a.changedTogether) {\\n        return b.changedTogether - a.changedTogether;\\n      }\\n      return b.lastSeen.localeCompare(a.lastSeen);\\n    })\\n    .slice(0, MAX_CLUSTERS);\\n}\\n\\n// ─── Public API ──────────────────────────────────────────────────────\\n\\n/**\\n * Load the project memory for `projectRoot`. If the file does not exist\\n * or is unreadable/corrupt, returns a fresh empty memory with the\\n * detected language pre-filled. Never throws.\\n */\\nexport async function loadMemory(projectRoot: string): Promise<ProjectMemory> {\\n  const root = resolve(projectRoot);\\n  const path = memoryPath(root);\\n  const language = await detectLanguage(root);\\n\\n  if (!(await fileExists(path))) {\\n    return emptyMemory(root, language);\\n  }\\n\\n  try {\\n    const raw = await readFile(path, \\\"utf8\\\");\\n    const parsed = JSON.parse(raw) as Partial<ProjectMemory>;\\n    return {\\n      projectRoot: root,\\n      language: typeof parsed.language === \\\"string\\\" && parsed.language.length > 0\\n        ? parsed.language\\n        : language,\\n      recentFiles: Array.isArray(parsed.recentFiles)\\n        ? parsed.recentFiles\\n            .filter((entry): entry is string => typeof entry === \\\"string\\\")\\n            .slice(0, MAX_FILES)\\n        : [],\\n      recentTasks: Array.isArray(parsed.recentTasks)\\n        ? parsed.recentTasks\\n            .filter(isTaskSummary)\\n            .slice(0, MAX_TASKS)\\n        : [],\\n      fileClusters: Array.isArray(parsed.fileClusters)\\n        ? parsed.fileClusters\\n            .filter(isFileCluster)\\n            .map((cluster) => ({\\n              files: normalizeTouchedFiles(cluster.files).slice(0, MAX_FILES),\\n              changedTogether: cluster.changedTogether,\\n              lastSeen: cluster.lastSeen,\\n            }))\\n            .slice(0, MAX_CLUSTERS)\\n        : [],\\n      taskPatterns: Array.isArray(parsed.taskPatterns)\\n        ? parsed.taskPatterns\\n            .filter(isTaskPatternProfile)\\n            .slice(0, MAX_PATTERNS)\\n        : [],\\n      updatedAt: typeof parsed.updatedAt === \\\"string\\\"\\n        ? parsed.updatedAt\\n        : new Date().toISOString(),\\n      schemaVersion: typeof parsed.schemaVersion === \\\"number\\\" ? parsed.schemaVersion : 1,\\n    };\\n  } catch {\\n    return emptyMemory(root, language);\\n  }\\n}\\n\\n/**\\n * Persist `memory` to {projectRoot}/.aedis/memory.json. Creates the\\n * .aedis directory if needed. Caps recentFiles/recentTasks to their\\n * maxima and refreshes `updatedAt` so callers don't have to.\\n */\\nexport async function saveMemory(\\n  projectRoot: string,\\n  memory: ProjectMemory,\\n): Promise<void> {\\n  const root = resolve(projectRoot);\\n  const path = memoryPath(root);\\n  await mkdir(dirname(path), { recursive: true });\\n\\n  const next: ProjectMemory = {\\n    projectRoot: root,\\n    language: memory.language,\\n    recentFiles: memory.recentFiles.slice(0, MAX_FILES),\\n    recentTasks: memory.recentTasks.slice(0, MAX_TASKS),\\n    fileClusters: memory.fileClusters.slice(0, MAX_CLUSTERS),\\n    taskPatterns: memory.taskPatterns.slice(0, MAX_PATTERNS),\\n    updatedAt: new Date().toISOString(),\\n    schemaVersion: memory.schemaVersion,\\n  };\\n\\n  // Atomic write under an advisory lock: the lock prevents two\\n  // concurrent runs on the same repo from silently clobbering each\\n  // other's updates; tmp+rename prevents torn writes if this\\n  // process crashes mid-save.\\n  await withRepoLock(path, async () => {\\n    const tmpPath = `${path}.tmp.${process.pid}`;\\n    await writeFile(tmpPath, JSON.stringify(next, null, 2), \\\"utf8\\\");\\n    await rename(tmpPath, path);\\n  });\\n}\\n\\n/**\\n * Record a finished task into the project memory and persist. The new\\n * task is prepended to `recentTasks`; any `filesTouched` are merged into\\n * `recentFiles` (most-recent-first, deduped, capped at 20). Multi-file\\n * tasks also update `fileClusters` so memory learns which files tend to\\n * move together. Returns the updated memory snapshot.\\n */\\nexport async function recordTask(\\n  projectRoot: string,\\n  taskSummary: TaskSummary,\\n): Promise<ProjectMemory> {\\n  const root = resolve(projectRoot);\\n  const path = memoryPath(root);\\n  // The read-modify-write must happen inside a single lock so two\\n  // concurrent runs don't each load the same base, update it, and\\n  // last-writer-wins one of them away. Both saveMemory and this\\n  // function acquire the same `path` lock, which is re-entrant only\\n  // if we release before re-acquiring — so we inline the write\\n  // instead of calling saveMemory.\\n  return withRepoLock(path, async () => {\\n    const memory = await loadMemory(projectRoot);\\n\\n    const touched = Array.isArray(taskSummary.filesTouched)\\n      ? normalizeTouchedFiles(taskSummary.filesTouched)\\n      : [];\\n\\n    const seen = new Set<string>();\\n    const recentFiles: string[] = [];\\n    for (const file of [...touched, ...memory.recentFiles]) {\\n      if (seen.has(file)) continue;\\n      seen.add(file);\\n      recentFiles.push(file);\\n      if (recentFiles.length >= MAX_FILES) break;\\n    }\\n\\n    const recentTasks = [taskSummary, ...memory.recentTasks].slice(0, MAX_TASKS);\\n    const fileClusters = updateFileClusters(memory.fileClusters, touched, taskSummary.timestamp);\\n    const taskPatterns = updateTaskPatterns(memory.taskPatterns ?? [], taskSummary, touched);\\n\\n    const next: ProjectMemory = {\\n      projectRoot: memory.projectRoot,\\n      language: memory.language,\\n      recentFiles: recentFiles.slice(0, MAX_FILES),\\n      recentTasks: recentTasks.slice(0, MAX_TASKS),\\n      fileClusters: fileClusters.slice(0, MAX_CLUSTERS),\\n      taskPatterns: taskPatterns.slice(0, MAX_PATTERNS),\\n      updatedAt: new Date().toISOString(),\\n      schemaVersion: memory.schemaVersion,\\n    };\\n\\n    await mkdir(dirname(path), { recursive: true });\\n    const tmpPath = `${path}.tmp.${process.pid}`;\\n    await writeFile(tmpPath, JSON.stringify(next, null, 2), \\\"utf8\\\");\\n    await rename(tmpPath, path);\\n    return next;\\n  });\\n}\\n\\n/**\\n * Reset the project memory to an empty state while preserving the detected\\n * language and project root. Useful for starting a fresh session without\\n * deleting the memory file itself.\\n */\\nexport async function clearMemory(projectRoot: string): Promise<ProjectMemory> {\\n  const memory = await loadMemory(projectRoot);\\n  const next: ProjectMemory = {\\n    projectRoot: memory.projectRoot,\\n    language: memory.language,\\n    recentFiles: [],\\n    recentTasks: [],\\n    fileClusters: [],\\n    taskPatterns: [],\\n    updatedAt: new Date().toISOString(),\\n    schemaVersion: memory.schemaVersion,\\n  };\\n  await saveMemory(projectRoot, next);\\n  return next;\\n}\\n\\n/**\\n * Delete the project memory file if it exists. Does not throw if the file\\n * is already missing. Useful for resetting project state completely.\\n */\\nexport async function deleteMemory(projectRoot: string): Promise<void> {\\n  const path = memoryPath(projectRoot);\\n  if (await fileExists(path)) {\\n    await unlink(path);\\n  }\\n}\\n\\n/**\\n * Returns the absolute path to the memory file for a given project root.\\n * Useful for external tooling, debugging, or manual inspection.\\n */\\nexport function getMemoryFilePath(projectRoot: string): string {\\n  return memoryPath(projectRoot);\\n}\\n\",\"lineCount\":733},{\"path\":\"core/context-gate.ts\",\"content\":\"import type { ProjectMemory } from \\\"./project-memory.js\\\";\\nimport type { ChangeSet } from \\\"./change-set.js\\\";\\nimport type { PlanWave } from \\\"./multi-file-planner.js\\\";\\nimport type { Invariant } from \\\"./invariant-extractor.js\\\";\\n\\nexport interface GatedContext {\\n  relevantFiles: string[];\\n  recentTaskSummaries: string[];\\n  language: string;\\n  clusterFiles?: string[];\\n  landmines?: string[];\\n  safeApproaches?: string[];\\n  memoryNotes?: string[];\\n  suggestedNextSteps?: string[];\\n  strictVerification?: boolean;\\n  /**\\n   * Shared invariants the current wave must respect. Populated only\\n   * when gating is wave-aware (see gateContextForWave). Empty on\\n   * plain gateContext calls so single-file runs don't see a token\\n   * bloat they don't need.\\n   */\\n  waveInvariants?: WaveInvariantRef[];\\n  /**\\n   * Sibling files drawn from the same wave — not the whole plan.\\n   * Included only when gating is wave-aware AND the sibling is likely\\n   * relevant (filename overlap with the prompt, or shared invariant\\n   * name). Minimal-context discipline is enforced by\\n   * MAX_WAVE_SIBLINGS.\\n   */\\n  waveSiblings?: string[];\\n  /**\\n   * Ordered log of reasons for every item we injected. Every entry\\n   * maps 1:1 to an item in relevantFiles / waveInvariants /\\n   * waveSiblings. The Coordinator prints this so reviewers can audit\\n   * what the gate showed the worker and why.\\n   */\\n  inclusionLog?: string[];\\n}\\n\\nexport interface WaveInvariantRef {\\n  readonly name: string;\\n  readonly type: Invariant[\\\"type\\\"];\\n  readonly description: string;\\n}\\n\\nconst MAX_RELEVANT_FILES = 10;\\nconst MAX_RECENT_TASKS = 3;\\nconst MAX_WAVE_INVARIANTS = 12;\\nconst MAX_WAVE_SIBLINGS = 6;\\nconst MAX_ARCHITECTURAL_HUB_FILES = 10;\\n\\n/**\\n * Base context gate — used when there is no wave context yet (single-file\\n * runs, scouting, pre-charter memory lookups). Keeps a flat, minimal\\n * signature so the hot path stays cheap.\\n */\\nexport function gateContext(memory: ProjectMemory, prompt: string): GatedContext {\\n  const words = extractPromptWords(prompt);\\n\\n  const recentFiles = memory.recentFiles ?? [];\\n  const relevantFiles = words.length === 0\\n    ? []\\n    : recentFiles\\n        .filter(path => {\\n          const normalizedPath = path.toLowerCase();\\n          return words.some(word => normalizedPath.includes(word));\\n        })\\n        .sort()\\n        .slice(0, MAX_RELEVANT_FILES);\\n\\n  const recentTasks = memory.recentTasks ?? [];\\n  const recentTaskSummaries = recentTasks\\n    .slice(0, MAX_RECENT_TASKS)\\n    .map(task => (task.resultSummary ?? task.prompt).slice(0, 120));\\n\\n  return {\\n    relevantFiles,\\n    recentTaskSummaries,\\n    language: memory.language ?? \\\"unknown\\\",\\n  };\\n}\\n\\nexport interface WaveContextInputs {\\n  readonly memory: ProjectMemory;\\n  readonly prompt: string;\\n  readonly changeSet: ChangeSet;\\n  readonly wave: PlanWave;\\n  /**\\n   * Target files the current worker has been assigned. Used to pick\\n   * siblings — we never return the target file itself as a sibling,\\n   * and we only pick from the wave's own file list.\\n   */\\n  readonly targetFiles: readonly string[];\\n}\\n\\n/**\\n * Wave-aware gate — used by the Coordinator when dispatching a builder\\n * inside a multi-file plan. Returns a GatedContext with:\\n *\\n *   - relevantFiles         — same base heuristic as gateContext\\n *   - waveInvariants        — only invariants whose `files` overlap\\n *                             the current wave's file set. Invariants\\n *                             that apply to later waves are deliberately\\n *                             withheld to preserve minimal-context\\n *                             discipline.\\n *   - waveSiblings          — files in the same wave, ranked by filename\\n *                             overlap with the prompt or shared\\n *                             invariant names. Capped at\\n *                             MAX_WAVE_SIBLINGS.\\n *   - inclusionLog          — one line per injected item explaining\\n *                             the reason (for Coordinator logging).\\n */\\nexport function gateContextForWave(inputs: WaveContextInputs): GatedContext {\\n  const { memory, prompt, changeSet, wave, targetFiles } = inputs;\\n  const base = gateContext(memory, prompt);\\n  const log: string[] = [];\\n\\n  for (const file of base.relevantFiles) {\\n    log.push(`relevant: ${file} — prompt word match on project memory`);\\n  }\\n\\n  const waveFiles = new Set(wave.files);\\n  const waveInvariants: WaveInvariantRef[] = [];\\n  for (const invariant of changeSet.invariants) {\\n    const touchesWave = invariant.files.some((f) => waveFiles.has(f));\\n    if (!touchesWave) continue;\\n\\n    waveInvariants.push({\\n      name: invariant.name,\\n      type: invariant.type,\\n      description: invariant.description,\\n    });\\n    log.push(\\n      `invariant: ${invariant.type}:${invariant.name} — touches ${invariant.files.filter((f) => waveFiles.has(f)).length} file(s) in wave ${wave.id}`,\\n    );\\n    if (waveInvariants.length >= MAX_WAVE_INVARIANTS) break;\\n  }\\n\\n  const words = extractPromptWords(prompt);\\n  const targetSet = new Set(targetFiles);\\n  const siblingCandidates = wave.files.filter((f) => !targetSet.has(f));\\n\\n  const rankedSiblings = siblingCandidates\\n    .map((file) => {\\n      const normalized = file.toLowerCase();\\n      const promptMatch = words.some((w) => normalized.includes(w));\\n      const sharesInvariant = waveInvariants.some((inv) =>\\n        changeSet.invariants.some(\\n          (i) => i.name === inv.name && i.files.includes(file),\\n        ),\\n      );\\n      return { file, promptMatch, sharesInvariant };\\n    })\\n    .filter((entry) => entry.promptMatch || entry.sharesInvariant)\\n    .slice(0, MAX_WAVE_SIBLINGS);\\n\\n  for (const entry of rankedSiblings) {\\n    const reasons: string[] = [];\\n    if (entry.promptMatch) reasons.push(\\\"prompt word match\\\");\\n    if (entry.sharesInvariant) reasons.push(\\\"shared invariant\\\");\\n    log.push(`sibling: ${entry.file} — ${reasons.join(\\\", \\\")}`);\\n  }\\n\\n  return {\\n    ...base,\\n    waveInvariants,\\n    waveSiblings: rankedSiblings.map((entry) => entry.file),\\n    inclusionLog: log,\\n  };\\n}\\n\\n/**\\n * Architectural-mode gate — triggered when scopeClassification.type === 'architectural'.\\n * Reads the repo index to find the top 10 most-connected files (files imported\\n * by the most other files), includes those as context regardless of prompt\\n * relevance, and injects a repo-wide summary at the top of every worker prompt.\\n */\\nexport function gateContextForArchitectural(\\n  memory: ProjectMemory,\\n  prompt: string,\\n  repoIndex: { file: string; importedByCount: number }[],\\n): GatedContext {\\n  const base = gateContext(memory, prompt);\\n  const log: string[] = [];\\n\\n  for (const file of base.relevantFiles) {\\n    log.push(`relevant: ${file} — prompt word match on project memory`);\\n  }\\n\\n  // Find top N most-connected hub files from the repo index\\n  const sorted = [...repoIndex]\\n    .sort((a, b) => b.importedByCount - a.importedByCount)\\n    .slice(0, MAX_ARCHITECTURAL_HUB_FILES);\\n\\n  const hubFiles = sorted.map((entry) => entry.file);\\n  for (const entry of sorted) {\\n    log.push(\\n      `hub: ${entry.file} — imported by ${entry.importedByCount} file(s) (architectural mode)`,\\n    );\\n  }\\n\\n  // Merge hub files into relevant files, deduped\\n  const allRelevant = uniqueStrings([...base.relevantFiles, ...hubFiles]);\\n\\n  const architecturalNote =\\n    `This is an architectural change. Key hub files: ${hubFiles.join(\\\", \\\")}. ` +\\n    `Proceed with awareness of downstream impact.`;\\n\\n  return {\\n    ...base,\\n    relevantFiles: allRelevant,\\n    memoryNotes: [...(base.memoryNotes ?? []), architecturalNote],\\n    inclusionLog: log,\\n  };\\n}\\n\\nexport function mergeGatedContext(base: GatedContext, overlay?: Partial<GatedContext>): GatedContext {\\n  if (!overlay) return base;\\n  return {\\n    relevantFiles: uniqueStrings([...base.relevantFiles, ...(overlay.relevantFiles ?? [])]),\\n    recentTaskSummaries: uniqueStrings([...base.recentTaskSummaries, ...(overlay.recentTaskSummaries ?? [])]).slice(0, MAX_RECENT_TASKS + 3),\\n    language: overlay.language ?? base.language,\\n    ...(mergeOptionalArrays(base.clusterFiles, overlay.clusterFiles, \\\"clusterFiles\\\")),\\n    ...(mergeOptionalArrays(base.landmines, overlay.landmines, \\\"landmines\\\")),\\n    ...(mergeOptionalArrays(base.safeApproaches, overlay.safeApproaches, \\\"safeApproaches\\\")),\\n    ...(mergeOptionalArrays(base.memoryNotes, overlay.memoryNotes, \\\"memoryNotes\\\")),\\n    ...(mergeOptionalArrays(base.suggestedNextSteps, overlay.suggestedNextSteps, \\\"suggestedNextSteps\\\")),\\n    ...(mergeOptionalArrays(base.waveInvariants, overlay.waveInvariants, \\\"waveInvariants\\\")),\\n    ...(mergeOptionalArrays(base.waveSiblings, overlay.waveSiblings, \\\"waveSiblings\\\")),\\n    ...(mergeOptionalArrays(base.inclusionLog, overlay.inclusionLog, \\\"inclusionLog\\\")),\\n    ...(overlay.strictVerification !== undefined ? { strictVerification: overlay.strictVerification } : base.strictVerification !== undefined ? { strictVerification: base.strictVerification } : {}),\\n  };\\n}\\n\\nfunction extractPromptWords(prompt: string): string[] {\\n  return Array.from(\\n    new Set(\\n      prompt\\n        .toLowerCase()\\n        .split(/\\\\s+/)\\n        .map(word => word.replace(/[^a-z0-9_-]/g, \\\"\\\"))\\n        .filter(word => word.length >= 4)\\n    )\\n  );\\n}\\n\\nfunction uniqueStrings(values: readonly string[]): string[] {\\n  return Array.from(new Set(values.filter((value): value is string => typeof value === \\\"string\\\" && value.length > 0)));\\n}\\n\\nfunction mergeOptionalArrays<T>(\\n  base: readonly T[] | undefined,\\n  overlay: readonly T[] | undefined,\\n  key: \\\"clusterFiles\\\" | \\\"landmines\\\" | \\\"safeApproaches\\\" | \\\"memoryNotes\\\" | \\\"suggestedNextSteps\\\" | \\\"waveInvariants\\\" | \\\"waveSiblings\\\" | \\\"inclusionLog\\\",\\n): Partial<GatedContext> {\\n  const values = [...(base ?? []), ...(overlay ?? [])];\\n  if (values.length === 0) return {};\\n  return {\\n    [key]: Array.from(new Set(values)),\\n  } as Partial<GatedContext>;\\n}\\n\",\"lineCount\":262},{\"path\":\"core/aedis-memory.ts\",\"content\":\"import { access, readFile } from \\\"node:fs/promises\\\";\\nimport { resolve, join } from \\\"node:path\\\";\\nimport { pathToFileURL } from \\\"node:url\\\";\\nimport type { ScopeClassification } from \\\"./scope-classifier.js\\\";\\nimport type { ProjectMemory } from \\\"./project-memory.js\\\";\\nimport type { GatedContext } from \\\"./context-gate.js\\\";\\nimport type { RunReceipt } from \\\"./coordinator.js\\\";\\nimport type { RunState } from \\\"./runstate.js\\\";\\nimport type { FileChange, WorkerResult } from \\\"../workers/base.js\\\";\\nimport type { VerificationReceipt } from \\\"./verification-pipeline.js\\\";\\nimport type { MergeDecision } from \\\"./merge-gate.js\\\";\\nimport type { RepairResult } from \\\"./repair-pass.js\\\";\\n\\ntype MemoryPrimitive = string | number | boolean | null;\\ntype MemoryValue = MemoryPrimitive | MemoryValue[] | { [key: string]: MemoryValue };\\n\\nexport interface MemoryEvidenceRef {\\n  kind: string;\\n  ref: string;\\n  note?: string;\\n  timestamp?: string;\\n  sourceSystem?: string;\\n}\\n\\nexport interface MemoryRelationship {\\n  type: string;\\n  targetId: string;\\n  note?: string;\\n}\\n\\nexport interface MemoryEntryRecord {\\n  id: string;\\n  space: string;\\n  kind: string;\\n  title: string;\\n  summary?: string;\\n  raw?: string;\\n  tags: string[];\\n  createdAt: string;\\n  updatedAt?: string;\\n  sourceSystem?: string;\\n  repoId?: string;\\n  filePaths?: string[];\\n  evidenceRefs?: MemoryEvidenceRef[];\\n  relatedIds?: string[];\\n  relationships?: MemoryRelationship[];\\n  confidence?: number;\\n  metadata?: Record<string, MemoryValue>;\\n}\\n\\nexport interface MemorySearchResult {\\n  entry: MemoryEntryRecord;\\n  score: number;\\n  reasons: string[];\\n}\\n\\nexport interface MemoryContextPack {\\n  entries: MemorySearchResult[];\\n  totalChars: number;\\n  rationale: string[];\\n}\\n\\nexport interface MemoryIngestInput extends Omit<MemoryEntryRecord, \\\"createdAt\\\"> {\\n  createdAt?: string;\\n}\\n\\nexport interface AedisMemoryRuntime {\\n  ingest: {\\n    remember(input: MemoryIngestInput): Promise<MemoryEntryRecord>;\\n  };\\n  retrieval: {\\n    retrieve(query: Record<string, unknown>): Promise<MemorySearchResult[]>;\\n  };\\n  contextGate: {\\n    buildContextPack(request: Record<string, unknown>): Promise<MemoryContextPack>;\\n  };\\n  store?: {\\n    getMany?(ids: string[]): Promise<MemoryEntryRecord[]>;\\n  };\\n}\\n\\nexport interface AedisExecutionContext {\\n  relevantFiles: string[];\\n  recentTaskSummaries: string[];\\n  clusterFiles: string[];\\n  landmines: string[];\\n  safeApproaches: string[];\\n  memoryNotes: string[];\\n  suggestedNextSteps: string[];\\n  inclusionLog: string[];\\n  strictVerification: boolean;\\n}\\n\\nexport interface BuildExecutionContextInput {\\n  projectRoot: string;\\n  prompt: string;\\n  projectMemory: ProjectMemory;\\n  scopeClassification?: ScopeClassification | null;\\n  targetFiles?: readonly string[];\\n}\\n\\nexport interface PersistRunMemoryInput {\\n  projectRoot: string;\\n  rawInput: string;\\n  normalizedPrompt: string;\\n  scopeClassification?: ScopeClassification | null;\\n  projectMemory: ProjectMemory;\\n  run: RunState;\\n  receipt: RunReceipt;\\n  changes: readonly FileChange[];\\n  workerResults: readonly WorkerResult[];\\n  verificationReceipt: VerificationReceipt | null;\\n  mergeDecision: MergeDecision | null;\\n  repairResult: RepairResult | null;\\n  commitSha: string | null;\\n}\\n\\ninterface RepoIndexFile {\\n  path: string;\\n  role: string;\\n  frameworkType: string;\\n  complexityEstimate: number;\\n  centralityScore: number;\\n  blastRadius: number;\\n  changeFrequency: number;\\n}\\n\\ninterface RepoIndexSnapshotLike {\\n  repoPath: string;\\n  updatedAt: string;\\n  files: RepoIndexFile[];\\n}\\n\\nconst DEFAULT_MEMORY_MODULE = process.env[\\\"AEDIS_LAB_MEMORY_MODULE\\\"] ?? \\\"/mnt/ai/squidley-v2/core/dist/memory/index.js\\\";\\nconst PROJECT_SPACE_PREFIX = \\\"aedis/project\\\";\\nconst RUNS_SPACE = \\\"aedis/runs\\\";\\nconst FAILURES_SPACE = \\\"aedis/failures\\\";\\nconst SUCCESS_SPACE = \\\"aedis/success\\\";\\nconst FILES_SPACE = \\\"aedis/files\\\";\\nconst SOURCE_SYSTEM = \\\"aedis\\\";\\n\\nexport class AedisMemoryAdapter {\\n  constructor(private readonly runtime: AedisMemoryRuntime) {}\\n\\n  async buildExecutionContext(input: BuildExecutionContextInput): Promise<AedisExecutionContext> {\\n    const repoId = repoIdentity(input.projectRoot);\\n    const targetFiles = uniqueStrings([...(input.targetFiles ?? [])]);\\n    const clusterFiles = await this.resolveClusterFiles(input.projectRoot, input.projectMemory, targetFiles);\\n    const scopedFiles = uniqueStrings([...targetFiles, ...clusterFiles]).slice(0, 10);\\n    const pack = await this.runtime.contextGate.buildContextPack({\\n      taskIntent: input.prompt,\\n      repoId,\\n      spaces: [projectSpace(repoId), RUNS_SPACE, FAILURES_SPACE, SUCCESS_SPACE, FILES_SPACE],\\n      ...(scopedFiles.length > 0 ? { filePaths: scopedFiles } : {}),\\n      maxEntries: 6,\\n      maxChars: 1800,\\n    });\\n\\n    const entries = pack.entries.map((result) => result.entry);\\n    const relevantFiles = uniqueStrings([\\n      ...scopedFiles,\\n      ...entries.flatMap((entry) => entry.filePaths ?? []),\\n    ]).slice(0, 10);\\n    const recentTaskSummaries = entries\\n      .filter((entry) => entry.kind === \\\"aedis-task\\\" || entry.kind === \\\"aedis-run\\\")\\n      .map((entry) => entry.summary ?? entry.title)\\n      .filter(Boolean)\\n      .slice(0, 4);\\n\\n    const landmines = summarizeLandmines(entries, targetFiles, await loadRepoIndexSnapshot(input.projectRoot));\\n    const safeApproaches = summarizeSuccessPatterns(entries).slice(0, 3);\\n    const memoryNotes = pack.entries\\n      .slice(0, 4)\\n      .map((result) => `${result.entry.title}: ${(result.entry.summary ?? \\\"\\\").slice(0, 140)}`.trim())\\n      .filter((line) => line.length > 0);\\n    const suggestedNextSteps = summarizeNextSteps(entries).slice(0, 3);\\n\\n    const inclusionLog = [\\n      ...(clusterFiles.length > 0 ? [`cluster: ${clusterFiles.join(\\\", \\\")} — related file-cluster history`] : []),\\n      ...pack.rationale.slice(0, 6),\\n      ...landmines.map((line) => `landmine: ${line}`),\\n    ];\\n\\n    return {\\n      relevantFiles,\\n      recentTaskSummaries,\\n      clusterFiles,\\n      landmines,\\n      safeApproaches,\\n      memoryNotes,\\n      suggestedNextSteps,\\n      inclusionLog,\\n      strictVerification: landmines.length > 0 || (input.scopeClassification?.blastRadius ?? 0) >= 6,\\n    };\\n  }\\n\\n  async persistRunMemory(input: PersistRunMemoryInput): Promise<{ suggestions: string[] }> {\\n    const repoId = repoIdentity(input.projectRoot);\\n    const filesTouched = uniqueStrings([\\n      ...input.changes.map((change) => change.path),\\n      ...input.run.filesTouched.map((touch) => touch.filePath),\\n    ]);\\n    const clusterFiles = await this.resolveClusterFiles(input.projectRoot, input.projectMemory, filesTouched);\\n    const suggestions = suggestFollowups(input.receipt, input.mergeDecision, input.verificationReceipt, input.repairResult, filesTouched, clusterFiles);\\n    const entries = buildRunMemoryEntries({\\n      ...input,\\n      repoId,\\n      filesTouched,\\n      clusterFiles,\\n      suggestions,\\n    });\\n    await Promise.all(entries.map((entry) => this.runtime.ingest.remember(entry)));\\n    return { suggestions };\\n  }\\n\\n  private async resolveClusterFiles(\\n    projectRoot: string,\\n    projectMemory: ProjectMemory,\\n    targetFiles: readonly string[],\\n  ): Promise<string[]> {\\n    const clusterPeers = projectMemory.fileClusters\\n      .filter((cluster) => cluster.files.some((file) => targetFiles.includes(file)))\\n      .flatMap((cluster) => cluster.files.filter((file) => !targetFiles.includes(file)));\\n\\n    const repoIndex = await loadRepoIndexSnapshot(projectRoot);\\n    if (!repoIndex) {\\n      return uniqueStrings(clusterPeers).slice(0, 6);\\n    }\\n\\n    const riskyRelated = repoIndex.files\\n      .filter((file) =>\\n        targetFiles.some((target) => sharesModule(target, file.path)) &&\\n        !targetFiles.includes(file.path) &&\\n        (file.blastRadius >= 4 || file.centralityScore >= 4),\\n      )\\n      .map((file) => file.path);\\n\\n    return uniqueStrings([...clusterPeers, ...riskyRelated]).slice(0, 6);\\n  }\\n}\\n\\nlet adapterPromise: Promise<AedisMemoryAdapter | null> | null = null;\\n\\nexport async function getAedisMemoryAdapter(): Promise<AedisMemoryAdapter | null> {\\n  if (!adapterPromise) {\\n    adapterPromise = loadAedisMemoryRuntime()\\n      .then((runtime) => runtime ? new AedisMemoryAdapter(runtime) : null)\\n      .catch(() => null);\\n  }\\n  return adapterPromise;\\n}\\n\\nexport function resetAedisMemoryAdapterForTests(): void {\\n  adapterPromise = null;\\n}\\n\\nexport function toGatedContext(memory: AedisExecutionContext, language: string): Partial<GatedContext> {\\n  return {\\n    relevantFiles: memory.relevantFiles,\\n    recentTaskSummaries: memory.recentTaskSummaries,\\n    language,\\n    ...(memory.clusterFiles.length > 0 ? { clusterFiles: memory.clusterFiles } : {}),\\n    ...(memory.landmines.length > 0 ? { landmines: memory.landmines } : {}),\\n    ...(memory.safeApproaches.length > 0 ? { safeApproaches: memory.safeApproaches } : {}),\\n    ...(memory.memoryNotes.length > 0 ? { memoryNotes: memory.memoryNotes } : {}),\\n    ...(memory.suggestedNextSteps.length > 0 ? { suggestedNextSteps: memory.suggestedNextSteps } : {}),\\n    ...(memory.inclusionLog.length > 0 ? { inclusionLog: memory.inclusionLog } : {}),\\n    strictVerification: memory.strictVerification,\\n  };\\n}\\n\\nasync function loadAedisMemoryRuntime(): Promise<AedisMemoryRuntime | null> {\\n  const candidates = [DEFAULT_MEMORY_MODULE];\\n  for (const candidate of candidates) {\\n    try {\\n      await access(candidate);\\n      const mod = await import(pathToFileURL(candidate).href) as { createMemorySubsystem?: () => Promise<AedisMemoryRuntime> };\\n      if (!mod.createMemorySubsystem) continue;\\n      return mod.createMemorySubsystem();\\n    } catch {\\n      continue;\\n    }\\n  }\\n  return null;\\n}\\n\\nfunction buildRunMemoryEntries(input: PersistRunMemoryInput & {\\n  repoId: string;\\n  filesTouched: string[];\\n  clusterFiles: string[];\\n  suggestions: string[];\\n}): MemoryIngestInput[] {\\n  const taskEntryId = `aedis-task:${input.receipt.runId}`;\\n  const runEntryId = `aedis-run:${input.receipt.runId}`;\\n  const projectSpaceId = projectSpace(input.repoId);\\n  const verificationVerdict = input.verificationReceipt?.verdict ?? \\\"not-run\\\";\\n  const outcomeSpace = input.receipt.verdict === \\\"success\\\" ? SUCCESS_SPACE : FAILURES_SPACE;\\n  const outcomeId = `aedis-outcome:${input.receipt.runId}`;\\n  const changeTypes = uniqueStrings(input.changes.map((change) => change.operation));\\n  const moduleTags = detectModuleTags(input.filesTouched);\\n  const evidenceRefs = buildEvidenceRefs(input);\\n  const relatedIds = [runEntryId, taskEntryId, outcomeId];\\n\\n  const entries: MemoryIngestInput[] = [\\n    {\\n      id: runEntryId,\\n      space: RUNS_SPACE,\\n      kind: \\\"aedis-run\\\",\\n      title: input.rawInput.slice(0, 160),\\n      summary: summarizeRun(input),\\n      raw: JSON.stringify({\\n        receipt: input.receipt,\\n        run: input.run,\\n        verificationReceipt: input.verificationReceipt,\\n        mergeDecision: input.mergeDecision,\\n        repairResult: input.repairResult,\\n      }, null, 2),\\n      tags: uniqueStrings([\\n        \\\"aedis-run\\\",\\n        `verdict:${input.receipt.verdict}`,\\n        `verification:${verificationVerdict}`,\\n        ...(input.scopeClassification ? [`scope:${input.scopeClassification.type}`] : []),\\n        ...moduleTags,\\n      ]),\\n      createdAt: input.receipt.timestamp,\\n      sourceSystem: SOURCE_SYSTEM,\\n      repoId: input.repoId,\\n      ...(input.filesTouched.length > 0 ? { filePaths: input.filesTouched } : {}),\\n      evidenceRefs,\\n      confidence: confidenceFromReceipt(input.receipt),\\n      metadata: {\\n        verdict: input.receipt.verdict,\\n        verificationVerdict,\\n        commitSha: input.commitSha ?? \\\"\\\",\\n        filesModified: input.receipt.summary.filesModified,\\n        scopeType: input.scopeClassification?.type ?? \\\"\\\",\\n        blastRadius: input.scopeClassification?.blastRadius ?? 0,\\n      },\\n    },\\n    {\\n      id: taskEntryId,\\n      space: projectSpaceId,\\n      kind: \\\"aedis-task\\\",\\n      title: input.normalizedPrompt.slice(0, 160),\\n      summary: summarizeTask(input),\\n      raw: JSON.stringify({\\n        rawInput: input.rawInput,\\n        normalizedPrompt: input.normalizedPrompt,\\n        workerResults: input.workerResults,\\n      }, null, 2),\\n      tags: uniqueStrings([\\n        \\\"aedis-task\\\",\\n        `verdict:${input.receipt.verdict}`,\\n        ...(input.scopeClassification ? [`scope:${input.scopeClassification.type}`] : []),\\n        ...changeTypes.map((type) => `change:${type}`),\\n        ...moduleTags,\\n      ]),\\n      createdAt: input.receipt.timestamp,\\n      sourceSystem: SOURCE_SYSTEM,\\n      repoId: input.repoId,\\n      ...(input.filesTouched.length > 0 ? { filePaths: input.filesTouched } : {}),\\n      evidenceRefs,\\n      relatedIds: [runEntryId, outcomeId],\\n      relationships: [\\n        { type: \\\"run\\\", targetId: runEntryId },\\n        { type: \\\"outcome\\\", targetId: outcomeId },\\n      ],\\n      confidence: confidenceFromReceipt(input.receipt),\\n      metadata: {\\n        scopeType: input.scopeClassification?.type ?? \\\"\\\",\\n        complexityTier: complexityTier(input.scopeClassification),\\n        verificationVerdict,\\n        filesTouched: input.filesTouched.length,\\n      },\\n    },\\n    {\\n      id: outcomeId,\\n      space: outcomeSpace,\\n      kind: input.receipt.verdict === \\\"success\\\" ? \\\"aedis-success\\\" : \\\"aedis-failure\\\",\\n      title: outcomeTitle(input),\\n      summary: summarizeOutcome(input),\\n      raw: JSON.stringify({\\n        issues: collectIssueMessages(input.workerResults),\\n        mergeDecision: input.mergeDecision,\\n        repairResult: input.repairResult,\\n      }, null, 2),\\n      tags: uniqueStrings([\\n        input.receipt.verdict === \\\"success\\\" ? \\\"success-pattern\\\" : \\\"failure-pattern\\\",\\n        `verification:${verificationVerdict}`,\\n        ...moduleTags,\\n      ]),\\n      createdAt: input.receipt.timestamp,\\n      sourceSystem: SOURCE_SYSTEM,\\n      repoId: input.repoId,\\n      ...(input.filesTouched.length > 0 ? { filePaths: input.filesTouched } : {}),\\n      evidenceRefs,\\n      relatedIds: [runEntryId, taskEntryId],\\n      relationships: [\\n        { type: \\\"run\\\", targetId: runEntryId },\\n        { type: \\\"task\\\", targetId: taskEntryId },\\n      ],\\n      confidence: confidenceFromReceipt(input.receipt),\\n      metadata: {\\n        verdict: input.receipt.verdict,\\n        verificationVerdict,\\n        primaryBlockReason: input.mergeDecision?.primaryBlockReason ?? \\\"\\\",\\n      },\\n    },\\n  ];\\n\\n  for (const file of input.filesTouched) {\\n    const peers = input.clusterFiles.filter((entry) => entry !== file).slice(0, 4);\\n    entries.push({\\n      id: `aedis-file:${input.receipt.runId}:${slugSegment(file)}`,\\n      space: FILES_SPACE,\\n      kind: \\\"aedis-file-touch\\\",\\n      title: file,\\n      summary: `${input.receipt.verdict} after ${changeTypes.join(\\\", \\\") || \\\"repo work\\\"} in ${file}`,\\n      raw: JSON.stringify({\\n        file,\\n        peers,\\n        scopeType: input.scopeClassification?.type ?? \\\"\\\",\\n      }, null, 2),\\n      tags: uniqueStrings([\\n        \\\"file-touch\\\",\\n        `verdict:${input.receipt.verdict}`,\\n        ...detectModuleTags([file]),\\n      ]),\\n      createdAt: input.receipt.timestamp,\\n      sourceSystem: SOURCE_SYSTEM,\\n      repoId: input.repoId,\\n      filePaths: [file],\\n      evidenceRefs,\\n      relatedIds,\\n      relationships: [\\n        { type: \\\"run\\\", targetId: runEntryId },\\n        { type: \\\"task\\\", targetId: taskEntryId },\\n        ...peers.map((peer) => ({ type: \\\"cluster-peer\\\", targetId: `file:${slugSegment(peer)}` })),\\n      ],\\n      metadata: {\\n        scopeType: input.scopeClassification?.type ?? \\\"\\\",\\n        clusterPeers: peers,\\n      },\\n    });\\n  }\\n\\n  if (input.suggestions.length > 0) {\\n    entries.push({\\n      id: `aedis-suggestions:${input.receipt.runId}`,\\n      space: projectSpaceId,\\n      kind: \\\"aedis-suggestions\\\",\\n      title: `Follow-up suggestions for ${input.receipt.runId}`,\\n      summary: input.suggestions.join(\\\" \\\"),\\n      tags: [\\\"suggestions\\\", `verdict:${input.receipt.verdict}`],\\n      createdAt: input.receipt.timestamp,\\n      sourceSystem: SOURCE_SYSTEM,\\n      repoId: input.repoId,\\n      ...(input.filesTouched.length > 0 ? { filePaths: input.filesTouched } : {}),\\n      evidenceRefs,\\n      relatedIds,\\n      relationships: [\\n        { type: \\\"run\\\", targetId: runEntryId },\\n        { type: \\\"task\\\", targetId: taskEntryId },\\n      ],\\n      metadata: {\\n        suggestionCount: input.suggestions.length,\\n      },\\n    });\\n  }\\n\\n  return entries;\\n}\\n\\nfunction summarizeRun(input: PersistRunMemoryInput & { filesTouched: string[] }): string {\\n  return [\\n    `${input.receipt.verdict} run`,\\n    input.scopeClassification ? `${input.scopeClassification.type} scope` : null,\\n    input.filesTouched.length > 0 ? `${input.filesTouched.length} file(s) touched` : \\\"no files touched\\\",\\n    input.verificationReceipt ? `verification ${input.verificationReceipt.verdict}` : \\\"verification not run\\\",\\n  ].filter(Boolean).join(\\\" · \\\");\\n}\\n\\nfunction summarizeTask(input: PersistRunMemoryInput & { filesTouched: string[] }): string {\\n  const topIssues = collectIssueMessages(input.workerResults).slice(0, 2).join(\\\" | \\\");\\n  return [\\n    input.scopeClassification ? `${input.scopeClassification.type}` : null,\\n    topIssues || summarizeRun(input),\\n  ].filter(Boolean).join(\\\" · \\\");\\n}\\n\\nfunction summarizeOutcome(input: PersistRunMemoryInput & { filesTouched: string[]; clusterFiles: string[] }): string {\\n  if (input.receipt.verdict === \\\"success\\\") {\\n    return [\\n      \\\"Successful approach stayed inside the requested scope.\\\",\\n      input.clusterFiles.length > 0 ? `Related cluster files: ${input.clusterFiles.join(\\\", \\\")}.` : null,\\n    ].filter(Boolean).join(\\\" \\\");\\n  }\\n  return [\\n    input.mergeDecision?.primaryBlockReason,\\n    input.repairResult && input.repairResult.issues.length > 0 ? `Repair-pass issues: ${input.repairResult.issues.slice(0, 2).join(\\\" | \\\")}` : null,\\n    input.verificationReceipt?.summary,\\n  ].filter(Boolean).join(\\\" \\\");\\n}\\n\\nfunction outcomeTitle(input: PersistRunMemoryInput): string {\\n  if (input.receipt.verdict === \\\"success\\\") {\\n    return `Successful run for ${input.normalizedPrompt.slice(0, 120)}`;\\n  }\\n  return `Failure in ${input.normalizedPrompt.slice(0, 120)}`;\\n}\\n\\nfunction buildEvidenceRefs(input: PersistRunMemoryInput): MemoryEvidenceRef[] {\\n  return uniqueEvidenceRefs([\\n    { kind: \\\"run\\\", ref: input.receipt.runId, sourceSystem: SOURCE_SYSTEM },\\n    { kind: \\\"intent\\\", ref: input.receipt.intentId, sourceSystem: SOURCE_SYSTEM },\\n    ...(input.commitSha ? [{ kind: \\\"commit\\\", ref: input.commitSha, sourceSystem: SOURCE_SYSTEM }] : []),\\n    ...(input.verificationReceipt ? [{ kind: \\\"verification\\\", ref: input.verificationReceipt.id, sourceSystem: SOURCE_SYSTEM }] : []),\\n  ]);\\n}\\n\\nfunction suggestFollowups(\\n  receipt: RunReceipt,\\n  mergeDecision: MergeDecision | null,\\n  verificationReceipt: VerificationReceipt | null,\\n  repairResult: RepairResult | null,\\n  filesTouched: readonly string[],\\n  clusterFiles: readonly string[],\\n): string[] {\\n  const suggestions: string[] = [];\\n  if (receipt.verdict !== \\\"success\\\") {\\n    suggestions.push(\\\"Re-run the task with tighter scope around the failing files before attempting broader changes.\\\");\\n  }\\n  if (mergeDecision?.action === \\\"block\\\" && mergeDecision.primaryBlockReason) {\\n    suggestions.push(`Address the merge blocker first: ${mergeDecision.primaryBlockReason}`);\\n  }\\n  if (verificationReceipt && verificationReceipt.verdict !== \\\"pass\\\") {\\n    suggestions.push(`Validate ${filesTouched.slice(0, 3).join(\\\", \\\") || \\\"the touched files\\\"} with focused verification before the next attempt.`);\\n  }\\n  if (repairResult && repairResult.issues.length > 0) {\\n    suggestions.push(`Inspect repair-pass fallout: ${repairResult.issues.slice(0, 2).join(\\\" | \\\")}`);\\n  }\\n  if (clusterFiles.length > 0) {\\n    suggestions.push(`Check nearby cluster files next: ${clusterFiles.slice(0, 3).join(\\\", \\\")}`);\\n  }\\n  return uniqueStrings(suggestions).slice(0, 4);\\n}\\n\\nfunction summarizeLandmines(\\n  entries: MemoryEntryRecord[],\\n  targetFiles: readonly string[],\\n  repoIndex: RepoIndexSnapshotLike | null,\\n): string[] {\\n  const fileFailureCounts = new Map<string, number>();\\n  for (const entry of entries) {\\n    if (entry.space !== FAILURES_SPACE) continue;\\n    for (const file of entry.filePaths ?? []) {\\n      fileFailureCounts.set(file, (fileFailureCounts.get(file) ?? 0) + 1);\\n    }\\n  }\\n\\n  const landmines: string[] = [];\\n  for (const file of targetFiles) {\\n    const failureCount = fileFailureCounts.get(file) ?? 0;\\n    if (failureCount >= 2) {\\n      landmines.push(`${file} has failed ${failureCount} times in prior Aedis runs.`);\\n    }\\n    const indexed = repoIndex?.files.find((entry) => entry.path === file);\\n    if (indexed && (indexed.blastRadius >= 5 || indexed.complexityEstimate >= 7)) {\\n      landmines.push(`${file} is a high-blast-radius area (${indexed.blastRadius}) with elevated complexity.`);\\n    }\\n  }\\n  return uniqueStrings(landmines).slice(0, 4);\\n}\\n\\nfunction summarizeSuccessPatterns(entries: MemoryEntryRecord[]): string[] {\\n  return entries\\n    .filter((entry) => entry.space === SUCCESS_SPACE || entry.tags.includes(\\\"success-pattern\\\"))\\n    .map((entry) => entry.summary ?? entry.title)\\n    .filter(Boolean)\\n    .slice(0, 3);\\n}\\n\\nfunction summarizeNextSteps(entries: MemoryEntryRecord[]): string[] {\\n  return entries\\n    .filter((entry) => entry.kind === \\\"aedis-suggestions\\\" || entry.tags.includes(\\\"suggestions\\\"))\\n    .map((entry) => entry.summary ?? entry.title)\\n    .filter(Boolean)\\n    .slice(0, 3);\\n}\\n\\nasync function loadRepoIndexSnapshot(projectRoot: string): Promise<RepoIndexSnapshotLike | null> {\\n  const path = join(resolve(projectRoot), \\\".aedis\\\", \\\"repo-index.json\\\");\\n  try {\\n    const raw = await readFile(path, \\\"utf-8\\\");\\n    const parsed = JSON.parse(raw) as RepoIndexSnapshotLike;\\n    if (!parsed || !Array.isArray(parsed.files)) return null;\\n    return parsed;\\n  } catch {\\n    return null;\\n  }\\n}\\n\\nfunction detectModuleTags(files: readonly string[]): string[] {\\n  return uniqueStrings(\\n    files.flatMap((file) => {\\n      const normalized = file.replace(/\\\\\\\\/g, \\\"/\\\");\\n      const parts = normalized.split(\\\"/\\\").filter(Boolean);\\n      const tags: string[] = [];\\n      if (parts[0]) tags.push(`module:${parts[0]}`);\\n      const ext = normalized.includes(\\\".\\\") ? normalized.slice(normalized.lastIndexOf(\\\".\\\") + 1) : \\\"\\\";\\n      if (ext) tags.push(`ext:${ext}`);\\n      return tags;\\n    }),\\n  );\\n}\\n\\nfunction confidenceFromReceipt(receipt: RunReceipt): number {\\n  switch (receipt.verdict) {\\n    case \\\"success\\\":\\n      return 0.85;\\n    case \\\"partial\\\":\\n      return 0.55;\\n    case \\\"failed\\\":\\n      return 0.35;\\n    default:\\n      return 0.2;\\n  }\\n}\\n\\nfunction complexityTier(scopeClassification?: ScopeClassification | null): string {\\n  if (!scopeClassification) return \\\"unknown\\\";\\n  if (scopeClassification.blastRadius >= 12) return \\\"high\\\";\\n  if (scopeClassification.blastRadius >= 6) return \\\"medium\\\";\\n  return \\\"low\\\";\\n}\\n\\nfunction collectIssueMessages(workerResults: readonly WorkerResult[]): string[] {\\n  return uniqueStrings(workerResults.flatMap((result) => result.issues.map((issue) => issue.message)));\\n}\\n\\nfunction projectSpace(repoId: string): string {\\n  return `${PROJECT_SPACE_PREFIX}/${slugSegment(repoId)}`;\\n}\\n\\nfunction repoIdentity(projectRoot: string): string {\\n  return resolve(projectRoot);\\n}\\n\\nfunction uniqueStrings(values: readonly string[]): string[] {\\n  return Array.from(new Set(values.map((value) => value.trim()).filter(Boolean)));\\n}\\n\\nfunction uniqueEvidenceRefs(values: readonly MemoryEvidenceRef[]): MemoryEvidenceRef[] {\\n  const seen = new Set<string>();\\n  const out: MemoryEvidenceRef[] = [];\\n  for (const value of values) {\\n    const key = `${value.kind}:${value.ref}`;\\n    if (seen.has(key)) continue;\\n    seen.add(key);\\n    out.push(value);\\n  }\\n  return out;\\n}\\n\\nfunction slugSegment(value: string): string {\\n  const cleaned = value.trim().toLowerCase().replace(/[^a-z0-9._-]+/g, \\\"-\\\").replace(/^-+|-+$/g, \\\"\\\");\\n  return cleaned || \\\"unknown\\\";\\n}\\n\\nfunction sharesModule(left: string, right: string): boolean {\\n  const l = left.replace(/\\\\\\\\/g, \\\"/\\\").split(\\\"/\\\")[0];\\n  const r = right.replace(/\\\\\\\\/g, \\\"/\\\").split(\\\"/\\\")[0];\\n  return Boolean(l && r && l === r);\\n}\\n\",\"lineCount\":675},{\"path\":\"core/blast-radius.ts\",\"content\":\"/**\\n * Blast Radius Estimator — Human-Readable Execution + Trust Layer v1.\\n *\\n * Wraps the numeric blast-radius score from `ScopeClassification`\\n * (computed in core/scope-classifier.ts) into a user-facing\\n * estimate with a risk level and a rationale the UI can render\\n * before execution begins.\\n *\\n * Why this is a separate module: ScopeClassification.blastRadius\\n * is an internal coordination number (file count + dependency\\n * pressure + keyword weight). It's fine for trust-routing but\\n * opaque to users. This module translates it into the three-bucket\\n * \\\"low / medium / high\\\" model the Lumen UI renders in the blast\\n * radius chip, and adds a one-line rationale grounded in the\\n * signals we already compute.\\n *\\n * The estimate is produced before execution begins (during Phase 1\\n * of the Coordinator's submit() pipeline) and is included in the\\n * final run summary for after-run comparison.\\n */\\n\\nimport type { ScopeClassification } from \\\"./scope-classifier.js\\\";\\nimport { classifyFileSensitivity } from \\\"./change-set.js\\\";\\n\\n// ─── Types ───────────────────────────────────────────────────────────\\n\\nexport type BlastRadiusLevel = \\\"low\\\" | \\\"medium\\\" | \\\"high\\\";\\n\\nexport interface BlastRadiusEstimate {\\n  readonly level: BlastRadiusLevel;\\n  /** Scope label from the classifier, passed through for the UI. */\\n  readonly scopeType: ScopeClassification[\\\"type\\\"] | \\\"unknown\\\";\\n  /**\\n   * Best-guess number of files likely to be touched. Rounded and\\n   * capped — this is a human display number, not a load-bearing\\n   * planning input.\\n   */\\n  readonly estimatedFiles: number;\\n  /** Raw numeric score from ScopeClassification for inspection. */\\n  readonly rawScore: number;\\n  /**\\n   * True when the scope classifier recommends decomposing the\\n   * change into smaller waves. Forwarded so the UI can show a\\n   * \\\"consider splitting\\\" hint.\\n   */\\n  readonly recommendDecompose: boolean;\\n  /** One-line human-readable rationale. */\\n  readonly rationale: string;\\n  /**\\n   * Short list of signals that contributed to the level. Useful\\n   * for tooltips (\\\"high because: migration keyword, 8+ files\\\").\\n   */\\n  readonly signals: readonly string[];\\n  /**\\n   * Sensitive file summary from the change manifest. Populated\\n   * when charterFiles are provided in the input.\\n   */\\n  readonly sensitiveFileSummary: SensitiveFileSummary;\\n  /**\\n   * Whether this blast radius estimate recommends blocking\\n   * autonomous apply — i.e., requiring explicit human approval\\n   * before changes are committed. True when critical files are\\n   * touched or blast radius is high with sensitive content.\\n   */\\n  readonly blockAutonomousApply: boolean;\\n}\\n\\nexport interface SensitiveFileSummary {\\n  readonly normalCount: number;\\n  readonly sensitiveCount: number;\\n  readonly criticalCount: number;\\n  readonly sensitiveFiles: readonly string[];\\n  readonly criticalFiles: readonly string[];\\n}\\n\\nexport interface BlastRadiusInput {\\n  readonly scopeClassification?: ScopeClassification | null;\\n  /** Number of target files in the charter (post-dedup). */\\n  readonly charterFileCount?: number;\\n  /** Optional prompt — lets us surface destructive verbs. */\\n  readonly prompt?: string;\\n  /** File paths from the change manifest — enables per-file sensitivity analysis. */\\n  readonly charterFiles?: readonly string[];\\n}\\n\\n// ─── Public API ──────────────────────────────────────────────────────\\n\\n/**\\n * Compute a human-readable blast radius estimate from the signals\\n * the Coordinator already has at planning time. Pure function.\\n */\\nexport function estimateBlastRadius(input: BlastRadiusInput): BlastRadiusEstimate {\\n  const scope = input.scopeClassification ?? null;\\n  const signals: string[] = [];\\n\\n  const rawScore = scope?.blastRadius ?? 0;\\n  const scopeType = scope?.type ?? \\\"unknown\\\";\\n  const recommendDecompose = scope?.recommendDecompose ?? false;\\n  const fileCount = input.charterFileCount ?? 0;\\n\\n  if (scope) signals.push(`scope:${scope.type}`);\\n  if (fileCount > 0) signals.push(`files:${fileCount}`);\\n  if (recommendDecompose) signals.push(\\\"decompose-recommended\\\");\\n\\n  // Destructive-verb detection on the prompt. These boost the\\n  // level even when the file count is low — a \\\"delete the auth\\n  // module\\\" task is high-risk regardless of file count.\\n  const lower = (input.prompt ?? \\\"\\\").toLowerCase();\\n  const destructive = /\\\\b(delete|drop|remove|rewrite|migrate|rename)\\\\b/.test(lower);\\n  if (destructive) signals.push(\\\"destructive-verb\\\");\\n  const security = /\\\\b(auth|token|secret|credential|password|permission)\\\\b/.test(lower);\\n  if (security) signals.push(\\\"security-sensitive\\\");\\n\\n  const level = chooseLevel({\\n    rawScore,\\n    scopeType,\\n    recommendDecompose,\\n    destructive,\\n    security,\\n  });\\n\\n  const estimatedFiles = estimateFileCount({ rawScore, fileCount, scopeType });\\n\\n  const rationale = buildRationale({\\n    level,\\n    scopeType,\\n    estimatedFiles,\\n    rawScore,\\n    recommendDecompose,\\n    destructive,\\n    security,\\n  });\\n\\n  const sensitiveFileSummary = analyzeSensitiveFiles(input.charterFiles ?? []);\\n  if (sensitiveFileSummary.criticalCount > 0) signals.push(`critical-files:${sensitiveFileSummary.criticalCount}`);\\n  if (sensitiveFileSummary.sensitiveCount > 0) signals.push(`sensitive-files:${sensitiveFileSummary.sensitiveCount}`);\\n\\n  // Block autonomous apply when critical files are touched, or\\n  // when high blast radius combines with any sensitive content.\\n  const blockAutonomousApply =\\n    sensitiveFileSummary.criticalCount > 0 ||\\n    (level === \\\"high\\\" && sensitiveFileSummary.sensitiveCount > 0) ||\\n    (destructive && security);\\n\\n  return {\\n    level,\\n    scopeType,\\n    estimatedFiles,\\n    rawScore,\\n    recommendDecompose,\\n    rationale,\\n    signals,\\n    sensitiveFileSummary,\\n    blockAutonomousApply,\\n  };\\n}\\n\\nfunction analyzeSensitiveFiles(files: readonly string[]): SensitiveFileSummary {\\n  let normalCount = 0;\\n  let sensitiveCount = 0;\\n  let criticalCount = 0;\\n  const sensitiveFiles: string[] = [];\\n  const criticalFiles: string[] = [];\\n\\n  for (const file of files) {\\n    const sensitivity = classifyFileSensitivity(file);\\n    switch (sensitivity) {\\n      case \\\"critical\\\":\\n        criticalCount++;\\n        criticalFiles.push(file);\\n        break;\\n      case \\\"sensitive\\\":\\n        sensitiveCount++;\\n        sensitiveFiles.push(file);\\n        break;\\n      default:\\n        normalCount++;\\n    }\\n  }\\n\\n  return { normalCount, sensitiveCount, criticalCount, sensitiveFiles, criticalFiles };\\n}\\n\\n// ─── Internals ───────────────────────────────────────────────────────\\n\\nfunction chooseLevel(input: {\\n  rawScore: number;\\n  scopeType: BlastRadiusEstimate[\\\"scopeType\\\"];\\n  recommendDecompose: boolean;\\n  destructive: boolean;\\n  security: boolean;\\n}): BlastRadiusLevel {\\n  // Architectural / migration scopes are high by definition.\\n  if (input.scopeType === \\\"architectural\\\" || input.scopeType === \\\"migration\\\") {\\n    return \\\"high\\\";\\n  }\\n  // Destructive verbs + security-sensitive surface → high even at\\n  // low raw score.\\n  if (input.destructive && input.security) return \\\"high\\\";\\n  // Raw score buckets, tuned to match the scope-classifier's own\\n  // thresholds (see classifyScope: blast=file+deps+2*keywords).\\n  if (input.rawScore >= 10) return \\\"high\\\";\\n  if (input.rawScore >= 4 || input.recommendDecompose) return \\\"medium\\\";\\n  if (input.destructive) return \\\"medium\\\";\\n  return \\\"low\\\";\\n}\\n\\nfunction estimateFileCount(input: {\\n  rawScore: number;\\n  fileCount: number;\\n  scopeType: BlastRadiusEstimate[\\\"scopeType\\\"];\\n}): number {\\n  // When the charter already names N files, trust it. Otherwise\\n  // fall back to a rough projection from the raw score.\\n  if (input.fileCount > 0) return input.fileCount;\\n  if (input.scopeType === \\\"architectural\\\") return Math.max(8, input.rawScore);\\n  if (input.scopeType === \\\"migration\\\") return Math.max(5, input.rawScore);\\n  if (input.scopeType === \\\"multi-file\\\") return Math.max(3, Math.ceil(input.rawScore / 2));\\n  if (input.scopeType === \\\"single-file\\\") return 1;\\n  return Math.max(1, Math.ceil(input.rawScore / 2));\\n}\\n\\nfunction buildRationale(input: {\\n  level: BlastRadiusLevel;\\n  scopeType: BlastRadiusEstimate[\\\"scopeType\\\"];\\n  estimatedFiles: number;\\n  rawScore: number;\\n  recommendDecompose: boolean;\\n  destructive: boolean;\\n  security: boolean;\\n}): string {\\n  const parts: string[] = [];\\n  parts.push(`~${input.estimatedFiles} file(s)`);\\n\\n  switch (input.scopeType) {\\n    case \\\"single-file\\\":\\n      parts.push(\\\"contained within one file\\\");\\n      break;\\n    case \\\"multi-file\\\":\\n      parts.push(\\\"spans multiple files\\\");\\n      break;\\n    case \\\"architectural\\\":\\n      parts.push(\\\"architectural change\\\");\\n      break;\\n    case \\\"migration\\\":\\n      parts.push(\\\"migration scope\\\");\\n      break;\\n    default:\\n      parts.push(\\\"scope unknown\\\");\\n  }\\n\\n  if (input.destructive) parts.push(\\\"destructive verbs\\\");\\n  if (input.security) parts.push(\\\"touches security-sensitive surface\\\");\\n  if (input.recommendDecompose) parts.push(\\\"planner recommends decomposing\\\");\\n\\n  return parts.join(\\\" · \\\") +\\n    ` (level=${input.level}, raw=${input.rawScore})`;\\n}\\n\",\"lineCount\":259},{\"path\":\"core/change-set.ts\",\"content\":\"import type { IntentObject } from \\\"./intent.js\\\";\\nimport type { Invariant } from \\\"./invariant-extractor.js\\\";\\nimport type { ImportGraph } from \\\"./import-graph.js\\\";\\n\\nexport type FileStatus =\\n  | \\\"planned\\\"\\n  | \\\"in-progress\\\"\\n  | \\\"blocked\\\"\\n  | \\\"complete\\\"\\n  | \\\"verified\\\"\\n  | \\\"failed\\\"\\n  | \\\"skipped\\\";\\n\\nexport type FileNecessity = \\\"required\\\" | \\\"optional\\\";\\n\\nexport type FileSensitivity = \\\"normal\\\" | \\\"sensitive\\\" | \\\"critical\\\";\\n\\nexport interface FileInclusion {\\n  readonly path: string;\\n  readonly whyIncluded: string;\\n  readonly dependsOn: readonly string[];\\n  readonly status: FileStatus;\\n  /**\\n   * Whether this file is required for the change to be coherent, or\\n   * optional (e.g. docs, ancillary tests). Optional file failures\\n   * degrade to warnings instead of blocking the run.\\n   */\\n  readonly necessity: FileNecessity;\\n  /**\\n   * Execution order hint — lower numbers execute first within the\\n   * same wave. Derived from dependency depth and file classification.\\n   * Zero-indexed.\\n   */\\n  readonly executionOrder: number;\\n  /**\\n   * Sensitivity classification for governance. Sensitive and critical\\n   * files lower confidence, trigger stronger review, and may block\\n   * autonomous apply.\\n   */\\n  readonly sensitivity: FileSensitivity;\\n  /**\\n   * Outcome of this file's processing at run completion. Null while\\n   * the run is still in progress.\\n   */\\n  readonly outcome: FileOutcome | null;\\n}\\n\\nexport interface FileOutcome {\\n  readonly status: \\\"succeeded\\\" | \\\"failed\\\" | \\\"skipped\\\" | \\\"rolled_back\\\";\\n  readonly reason: string;\\n  /** Wave this file was processed in, if applicable. */\\n  readonly waveId: number | null;\\n}\\n\\nexport interface CoherenceVerdict {\\n  readonly coherent: boolean;\\n  readonly reason: string;\\n}\\n\\nexport interface ChangeSet {\\n  readonly intent: IntentObject;\\n  readonly filesInScope: readonly FileInclusion[];\\n  readonly dependencyRelationships: Readonly<Record<string, readonly string[]>>;\\n  readonly invariants: readonly Invariant[];\\n  readonly sharedInvariants: readonly string[];\\n  readonly acceptanceCriteria: readonly string[];\\n  readonly coherenceVerdict: CoherenceVerdict;\\n}\\n\\nfunction normalizeFiles(files: readonly string[]): string[] {\\n  return Array.from(\\n    new Set(\\n      files\\n        .map((file) => file.trim())\\n        .filter((file) => file.length > 0),\\n    ),\\n  );\\n}\\n\\n// ─── Sensitive File Detection ────────────────────────────────────────\\n\\nconst CRITICAL_FILE_PATTERNS = [\\n  /\\\\bauth\\\\b/i,\\n  /\\\\bsecret/i,\\n  /\\\\bcredential/i,\\n  /\\\\bpassword/i,\\n  /\\\\btoken/i,\\n  /\\\\bpermission/i,\\n  /\\\\.env($|\\\\.)/,\\n  /\\\\.(pem|key|cert)$/,\\n];\\n\\nconst SENSITIVE_FILE_PATTERNS = [\\n  /^package\\\\.json$/,\\n  /^package-lock\\\\.json$/,\\n  /^pnpm-lock\\\\.yaml$/,\\n  /^yarn\\\\.lock$/,\\n  /^tsconfig.*\\\\.json$/,\\n  /^\\\\.eslintrc/,\\n  /^\\\\.prettierrc/,\\n  /^Dockerfile/,\\n  /^docker-compose/,\\n  /\\\\.ya?ml$/,\\n  /^Makefile$/,\\n  /^\\\\.github\\\\//,\\n  /^\\\\.gitlab-ci/,\\n  /^jest\\\\.config/,\\n  /^vitest\\\\.config/,\\n  /^vite\\\\.config/,\\n  /^next\\\\.config/,\\n  /^webpack\\\\.config/,\\n  /\\\\bmigration/i,\\n  /\\\\bschema\\\\b.*\\\\.(sql|prisma|graphql)$/i,\\n  /^index\\\\.[jt]sx?$/,\\n  /\\\\/index\\\\.[jt]sx?$/,\\n];\\n\\nexport function classifyFileSensitivity(filePath: string): FileSensitivity {\\n  const normalized = filePath.replace(/\\\\\\\\/g, \\\"/\\\");\\n  const basename = normalized.includes(\\\"/\\\") ? normalized.slice(normalized.lastIndexOf(\\\"/\\\") + 1) : normalized;\\n\\n  if (CRITICAL_FILE_PATTERNS.some((pattern) => pattern.test(normalized) || pattern.test(basename))) {\\n    return \\\"critical\\\";\\n  }\\n  if (SENSITIVE_FILE_PATTERNS.some((pattern) => pattern.test(normalized) || pattern.test(basename))) {\\n    return \\\"sensitive\\\";\\n  }\\n  return \\\"normal\\\";\\n}\\n\\nfunction classifyNecessity(intent: IntentObject, file: string): FileNecessity {\\n  const normalized = file.toLowerCase();\\n\\n  // Test files and docs are optional — their failure shouldn't block\\n  if (\\n    normalized.includes(\\\"test\\\") ||\\n    normalized.includes(\\\"spec\\\") ||\\n    normalized.endsWith(\\\".md\\\") ||\\n    normalized.includes(\\\"docs/\\\") ||\\n    normalized.includes(\\\"__mocks__\\\")\\n  ) {\\n    return \\\"optional\\\";\\n  }\\n\\n  // Files explicitly listed in deliverables are required\\n  const isDeliverable = intent.charter.deliverables.some((d) =>\\n    d.targetFiles.some((t) => t === file),\\n  );\\n  if (isDeliverable) return \\\"required\\\";\\n\\n  return \\\"required\\\";\\n}\\n\\nfunction computeExecutionOrder(file: string, dependencyMap: Map<string, string[]>): number {\\n  const deps = dependencyMap.get(file) ?? [];\\n  if (deps.length === 0) return 0;\\n\\n  // Simple depth: count max chain length\\n  const visited = new Set<string>();\\n  function depth(f: string): number {\\n    if (visited.has(f)) return 0;\\n    visited.add(f);\\n    const fileDeps = dependencyMap.get(f) ?? [];\\n    if (fileDeps.length === 0) return 0;\\n    return 1 + Math.max(...fileDeps.map(depth));\\n  }\\n\\n  return depth(file);\\n}\\n\\nfunction inferWhyIncluded(intent: IntentObject, file: string): string {\\n  const deliverable = intent.charter.deliverables.find((entry) => entry.targetFiles.includes(file));\\n\\n  if (deliverable) {\\n    return `${deliverable.type} required for deliverable: ${deliverable.description}`;\\n  }\\n\\n  if (intent.charter.objective.toLowerCase().includes(file.toLowerCase())) {\\n    return `Referenced directly by charter objective: ${intent.charter.objective}`;\\n  }\\n\\n  return `Included to satisfy intent objective: ${intent.charter.objective}`;\\n}\\n\\nfunction inferDependencies(files: readonly string[]): Map<string, string[]> {\\n  const byDirectory = new Map<string, string[]>();\\n  const dependencies = new Map<string, string[]>();\\n\\n  for (const file of files) {\\n    const directory = file.includes(\\\"/\\\") ? file.slice(0, file.lastIndexOf(\\\"/\\\")) : \\\".\\\";\\n    const group = byDirectory.get(directory) ?? [];\\n    group.push(file);\\n    byDirectory.set(directory, group);\\n  }\\n\\n  for (const file of files) {\\n    const directory = file.includes(\\\"/\\\") ? file.slice(0, file.lastIndexOf(\\\"/\\\")) : \\\".\\\";\\n    const siblingFiles = (byDirectory.get(directory) ?? []).filter((candidate) => candidate !== file);\\n    const inferred = siblingFiles\\n      .filter((candidate) => candidate.length <= file.length || candidate.endsWith(\\\".d.ts\\\"))\\n      .slice(0, 4);\\n    dependencies.set(file, inferred);\\n  }\\n\\n  return dependencies;\\n}\\n\\n/**\\n * Derive dependencies from a real ImportGraph. For each file in\\n * scope, returns the other in-scope files it imports (direct deps\\n * within the change set).\\n */\\nfunction inferDependenciesFromGraph(\\n  files: readonly string[],\\n  graph: ImportGraph,\\n): Map<string, string[]> {\\n  const fileSet = new Set(files);\\n  const dependencies = new Map<string, string[]>();\\n\\n  for (const file of files) {\\n    // Direct imports that are also in the change set\\n    const imports = graph.getImports(file).filter((dep) => fileSet.has(dep));\\n    // Also include files that import this file (reverse deps within scope)\\n    // — these are files that will break if this file changes\\n    const consumers = graph.getImportedBy(file).filter((dep) => fileSet.has(dep));\\n    // Combine and deduplicate — a file depends on its imports AND\\n    // is depended on by its consumers, both matter for ordering\\n    const combined = [...new Set([...imports, ...consumers])].filter((dep) => dep !== file);\\n    dependencies.set(file, combined);\\n  }\\n\\n  return dependencies;\\n}\\n\\nfunction collectSharedInvariants(intent: IntentObject, files: readonly string[]): string[] {\\n  const invariants = new Set<string>();\\n\\n  invariants.add(`Stay within declared intent objective: ${intent.charter.objective}`);\\n  invariants.add(`Respect exclusions: ${intent.exclusions.join(\\\", \\\") || \\\"none\\\"}`);\\n  invariants.add(`Keep affected files coherent across ${files.length} in-scope file(s)`);\\n\\n  for (const criterion of intent.charter.successCriteria) {\\n    invariants.add(`Preserve success criterion: ${criterion}`);\\n  }\\n\\n  return [...invariants];\\n}\\n\\nfunction deriveAcceptanceCriteria(intent: IntentObject, files: readonly string[]): string[] {\\n  const criteria = [...intent.charter.successCriteria];\\n  criteria.push(`All in-scope files remain internally consistent: ${files.join(\\\", \\\") || \\\"none\\\"}`);\\n  criteria.push(\\\"Dependency relationships are respected during implementation order.\\\");\\n  return criteria;\\n}\\n\\nfunction deriveCoherenceVerdict(\\n  files: readonly string[],\\n  dependencyRelationships: Readonly<Record<string, readonly string[]>>,\\n): CoherenceVerdict {\\n  if (files.length === 0) {\\n    return {\\n      coherent: false,\\n      reason: \\\"No files were provided for the change set.\\\",\\n    };\\n  }\\n\\n  const orphaned = files.filter((file) => !(file in dependencyRelationships));\\n  if (orphaned.length > 0) {\\n    return {\\n      coherent: false,\\n      reason: `Missing dependency metadata for: ${orphaned.join(\\\", \\\")}`,\\n    };\\n  }\\n\\n  return {\\n    coherent: true,\\n    reason: `Change set covers ${files.length} file(s) with dependency metadata and acceptance criteria.`,\\n  };\\n}\\n\\n/**\\n * Create a ChangeSet with optional ImportGraph-backed dependency\\n * inference. When an ImportGraph is provided, dependencies are\\n * derived from real import/require relationships instead of the\\n * directory-sibling heuristic fallback.\\n */\\nexport function createChangeSet(\\n  intent: IntentObject,\\n  files: readonly string[],\\n  importGraph?: ImportGraph | null,\\n): ChangeSet {\\n  const normalizedFiles = normalizeFiles(files);\\n\\n  // Use real import data when available, fall back to heuristic\\n  const dependencyMap = importGraph\\n    ? inferDependenciesFromGraph(normalizedFiles, importGraph)\\n    : inferDependencies(normalizedFiles);\\n\\n  const filesInScope: FileInclusion[] = normalizedFiles.map((file) => ({\\n    path: file,\\n    whyIncluded: inferWhyIncluded(intent, file),\\n    dependsOn: dependencyMap.get(file) ?? [],\\n    status: \\\"planned\\\",\\n    necessity: classifyNecessity(intent, file),\\n    executionOrder: computeExecutionOrder(file, dependencyMap),\\n    sensitivity: classifyFileSensitivity(file),\\n    outcome: null,\\n  }));\\n\\n  const dependencyRelationships = Object.freeze(\\n    Object.fromEntries(\\n      normalizedFiles.map((file) => [file, Object.freeze([...(dependencyMap.get(file) ?? [])])]),\\n    ) as Record<string, readonly string[]>,\\n  );\\n\\n  const sharedInvariants = Object.freeze(collectSharedInvariants(intent, normalizedFiles));\\n  const acceptanceCriteria = Object.freeze(deriveAcceptanceCriteria(intent, normalizedFiles));\\n  const coherenceVerdict = deriveCoherenceVerdict(normalizedFiles, dependencyRelationships);\\n\\n  return Object.freeze({\\n    intent,\\n    filesInScope: Object.freeze(filesInScope.map((entry) => Object.freeze(entry))),\\n    dependencyRelationships,\\n    invariants: Object.freeze([]),\\n    sharedInvariants,\\n    acceptanceCriteria,\\n    coherenceVerdict: Object.freeze(coherenceVerdict),\\n  });\\n}\\n\\n// ─── Manifest Queries ───────────────────────────────────────────────\\n\\n/** Count files by sensitivity level. */\\nexport function countSensitiveFiles(changeSet: ChangeSet): { normal: number; sensitive: number; critical: number } {\\n  const counts = { normal: 0, sensitive: 0, critical: 0 };\\n  for (const file of changeSet.filesInScope) {\\n    counts[file.sensitivity]++;\\n  }\\n  return counts;\\n}\\n\\n/** Get files sorted by execution order. */\\nexport function getExecutionOrder(changeSet: ChangeSet): readonly FileInclusion[] {\\n  return [...changeSet.filesInScope].sort((a, b) => a.executionOrder - b.executionOrder);\\n}\\n\\n/** Check if any required files have a terminal failure status. */\\nexport function hasRequiredFileFailures(changeSet: ChangeSet): boolean {\\n  return changeSet.filesInScope.some(\\n    (f) => f.necessity === \\\"required\\\" && (f.status === \\\"failed\\\" || f.outcome?.status === \\\"failed\\\"),\\n  );\\n}\\n\\n/** Produce a per-file outcome summary for receipts. */\\nexport function summarizeFileOutcomes(changeSet: ChangeSet): readonly FileOutcomeSummary[] {\\n  return changeSet.filesInScope.map((f) => ({\\n    path: f.path,\\n    necessity: f.necessity,\\n    sensitivity: f.sensitivity,\\n    status: f.outcome?.status ?? (f.status === \\\"verified\\\" || f.status === \\\"complete\\\" ? \\\"succeeded\\\" : \\\"pending\\\"),\\n    reason: f.outcome?.reason ?? f.status,\\n    waveId: f.outcome?.waveId ?? null,\\n  }));\\n}\\n\\nexport interface FileOutcomeSummary {\\n  readonly path: string;\\n  readonly necessity: FileNecessity;\\n  readonly sensitivity: FileSensitivity;\\n  readonly status: \\\"succeeded\\\" | \\\"failed\\\" | \\\"skipped\\\" | \\\"rolled_back\\\" | \\\"pending\\\";\\n  readonly reason: string;\\n  readonly waveId: number | null;\\n}\\n\",\"lineCount\":374},{\"path\":\"core/charter.ts\",\"content\":\"/**\\n * CharterGenerator — Turns a one-sentence user request into a structured build objective.\\n *\\n * The Charter is the \\\"what and why\\\" of a build run. It decomposes vague intent\\n * into concrete deliverables, success criteria, and a quality bar. The Coordinator\\n * feeds the Charter into the IntentObject before any worker sees it.\\n */\\n\\nimport type {\\n  Charter,\\n  Constraint,\\n  Deliverable,\\n  QualityBar,\\n} from \\\"./intent.js\\\";\\n\\n// ─── Analysis Types ──────────────────────────────────────────────────\\n\\nexport interface RequestAnalysis {\\n  /** The raw user request */\\n  raw: string;\\n  /** Detected intent category */\\n  category: RequestCategory;\\n  /** Extracted target files/modules if mentioned */\\n  targets: string[];\\n  /** Detected scope size */\\n  scopeEstimate: \\\"trivial\\\" | \\\"small\\\" | \\\"medium\\\" | \\\"large\\\" | \\\"epic\\\";\\n  /** Detected risk signals */\\n  riskSignals: string[];\\n  /** Ambiguities that need resolution or assumptions */\\n  ambiguities: string[];\\n}\\n\\nexport type RequestCategory =\\n  | \\\"feature\\\"\\n  | \\\"bugfix\\\"\\n  | \\\"refactor\\\"\\n  | \\\"scaffold\\\"\\n  | \\\"config\\\"\\n  | \\\"test\\\"\\n  | \\\"docs\\\"\\n  | \\\"investigation\\\";\\n\\n// ─── Charter Generation ──────────────────────────────────────────────\\n\\nexport interface CharterGeneratorConfig {\\n  /** Default quality bar when not inferrable from request */\\n  defaultQualityBar: QualityBar;\\n  /** Maximum deliverables before requiring scope split */\\n  maxDeliverables: number;\\n  /** Whether to auto-add test deliverables for code changes */\\n  autoTestDeliverables: boolean;\\n}\\n\\nconst DEFAULT_CONFIG: CharterGeneratorConfig = {\\n  defaultQualityBar: \\\"standard\\\",\\n  maxDeliverables: 12,\\n  autoTestDeliverables: true,\\n};\\n\\nexport class CharterGenerator {\\n  private config: CharterGeneratorConfig;\\n\\n  constructor(config: Partial<CharterGeneratorConfig> = {}) {\\n    this.config = { ...DEFAULT_CONFIG, ...config };\\n  }\\n\\n  /**\\n   * Analyze a raw user request into structured signals.\\n   * This is the first pass — no LLM needed for basic classification.\\n   */\\n  analyzeRequest(request: string): RequestAnalysis {\\n    const lower = request.toLowerCase();\\n\\n    const category = this.classifyCategory(lower);\\n    const targets = this.extractTargets(request);\\n    const scopeEstimate = this.estimateScope(lower, targets);\\n    const riskSignals = this.detectRiskSignals(lower);\\n    const ambiguities = this.detectAmbiguities(lower, targets);\\n\\n    return {\\n      raw: request,\\n      category,\\n      targets,\\n      scopeEstimate,\\n      riskSignals,\\n      ambiguities,\\n    };\\n  }\\n\\n  /**\\n   * Generate a Charter from a RequestAnalysis.\\n   * For complex requests, this should be augmented by an LLM call —\\n   * this method provides the deterministic scaffold.\\n   */\\n  generateCharter(analysis: RequestAnalysis): Charter {\\n    const objective = this.buildObjective(analysis);\\n    const successCriteria = this.buildSuccessCriteria(analysis);\\n    const deliverables = this.buildDeliverables(analysis);\\n    const qualityBar = this.determineQualityBar(analysis);\\n\\n    if (deliverables.length > this.config.maxDeliverables) {\\n      throw new CharterScopeError(\\n        `Request produces ${deliverables.length} deliverables (max ${this.config.maxDeliverables}). ` +\\n          `Split into smaller requests or raise maxDeliverables.`\\n      );\\n    }\\n\\n    return { objective, successCriteria, deliverables, qualityBar };\\n  }\\n\\n  /**\\n   * Generate default constraints based on analysis.\\n   * The Coordinator may add more before sealing the IntentObject.\\n   */\\n  generateDefaultConstraints(analysis: RequestAnalysis): Constraint[] {\\n    const constraints: Constraint[] = [\\n      {\\n        kind: \\\"rollback\\\",\\n        description: \\\"All changes must be revertible via git reset\\\",\\n        hard: true,\\n      },\\n      {\\n        kind: \\\"governance\\\",\\n        description: \\\"Every file change must trace to a deliverable in the charter\\\",\\n        hard: true,\\n      },\\n    ];\\n\\n    if (analysis.riskSignals.length > 0) {\\n      constraints.push({\\n        kind: \\\"scope\\\",\\n        description: `Risk signals detected: ${analysis.riskSignals.join(\\\", \\\")}. Require Critic review before apply.`,\\n        hard: true,\\n      });\\n    }\\n\\n    if (analysis.scopeEstimate === \\\"large\\\" || analysis.scopeEstimate === \\\"epic\\\") {\\n      constraints.push({\\n        kind: \\\"budget\\\",\\n        description: \\\"Large scope — require cost estimate before execution\\\",\\n        hard: false,\\n      });\\n    }\\n\\n    return constraints;\\n  }\\n\\n  // ─── Private: Classification ─────────────────────────────────────\\n\\n  private classifyCategory(lower: string): RequestCategory {\\n    if (/\\\\b(fix|bug|broken|crash|error|issue)\\\\b/.test(lower)) return \\\"bugfix\\\";\\n    if (/\\\\b(refactor|clean|restructure|reorganize|extract)\\\\b/.test(lower)) return \\\"refactor\\\";\\n    if (/\\\\b(scaffold|create|init|bootstrap|setup|new repo)\\\\b/.test(lower)) return \\\"scaffold\\\";\\n    if (/\\\\b(test|spec|coverage)\\\\b/.test(lower)) return \\\"test\\\";\\n    if (/\\\\b(config|env|setting|toggle)\\\\b/.test(lower)) return \\\"config\\\";\\n    if (/\\\\b(doc|readme|explain|document)\\\\b/.test(lower)) return \\\"docs\\\";\\n    if (/\\\\b(investigate|explore|understand|audit|check)\\\\b/.test(lower)) return \\\"investigation\\\";\\n    return \\\"feature\\\";\\n  }\\n\\n  private extractTargets(request: string): string[] {\\n    const filePatterns = request.match(/[\\\\w\\\\-./]+\\\\.(ts|tsx|js|jsx|json|md|yaml|yml)/g);\\n    const dirPatterns = request.match(/(?:src|lib|core|modules|apps|workers|router)\\\\/[\\\\w\\\\-./]*/g);\\n    return [...new Set([...(filePatterns ?? []), ...(dirPatterns ?? [])])];\\n  }\\n\\n  private estimateScope(\\n    lower: string,\\n    targets: string[]\\n  ): RequestAnalysis[\\\"scopeEstimate\\\"] {\\n    if (targets.length > 10) return \\\"epic\\\";\\n    if (targets.length > 5) return \\\"large\\\";\\n    if (targets.length > 2) return \\\"medium\\\";\\n    if (/\\\\b(all|every|entire|whole|across)\\\\b/.test(lower)) return \\\"large\\\";\\n    if (/\\\\b(simple|quick|small|minor|tiny)\\\\b/.test(lower)) return \\\"trivial\\\";\\n    return \\\"small\\\";\\n  }\\n\\n  private detectRiskSignals(lower: string): string[] {\\n    const signals: string[] = [];\\n    if (/\\\\b(delete|remove|drop|destroy)\\\\b/.test(lower)) signals.push(\\\"destructive-operation\\\");\\n    if (/\\\\b(database|db|migration|schema)\\\\b/.test(lower)) signals.push(\\\"data-layer\\\");\\n    if (/\\\\b(auth|token|secret|credential|password)\\\\b/.test(lower)) signals.push(\\\"security-sensitive\\\");\\n    if (/\\\\b(deploy|prod|production|release)\\\\b/.test(lower)) signals.push(\\\"production-facing\\\");\\n    if (/\\\\b(api|endpoint|route|public)\\\\b/.test(lower)) signals.push(\\\"public-interface\\\");\\n    return signals;\\n  }\\n\\n  private detectAmbiguities(lower: string, targets: string[]): string[] {\\n    const ambiguities: string[] = [];\\n    if (targets.length === 0) ambiguities.push(\\\"No specific files/modules mentioned\\\");\\n    if (/\\\\b(maybe|possibly|might|could|or)\\\\b/.test(lower))\\n      ambiguities.push(\\\"Request contains hedging language\\\");\\n    if (/\\\\b(better|improve|clean up|nice)\\\\b/.test(lower))\\n      ambiguities.push(\\\"Subjective quality target — needs concrete criteria\\\");\\n    return ambiguities;\\n  }\\n\\n  // ─── Private: Charter Building ───────────────────────────────────\\n\\n  private buildObjective(analysis: RequestAnalysis): string {\\n    const prefix: Record<RequestCategory, string> = {\\n      feature: \\\"Implement\\\",\\n      bugfix: \\\"Fix\\\",\\n      refactor: \\\"Refactor\\\",\\n      scaffold: \\\"Scaffold\\\",\\n      config: \\\"Configure\\\",\\n      test: \\\"Add test coverage for\\\",\\n      docs: \\\"Document\\\",\\n      investigation: \\\"Investigate\\\",\\n    };\\n    return `${prefix[analysis.category]}: ${analysis.raw}`;\\n  }\\n\\n  private buildSuccessCriteria(analysis: RequestAnalysis): string[] {\\n    const criteria: string[] = [\\n      \\\"All deliverables completed as specified\\\",\\n      \\\"No regressions in existing tests\\\",\\n      \\\"Changes are reviewable and revertible\\\",\\n    ];\\n\\n    if (analysis.category === \\\"bugfix\\\") {\\n      criteria.push(\\\"Bug no longer reproducible with original reproduction steps\\\");\\n    }\\n    if (analysis.category === \\\"feature\\\" || analysis.category === \\\"scaffold\\\") {\\n      criteria.push(\\\"New code has corresponding test coverage\\\");\\n    }\\n    if (analysis.riskSignals.includes(\\\"public-interface\\\")) {\\n      criteria.push(\\\"Public API changes are backwards-compatible or versioned\\\");\\n    }\\n\\n    return criteria;\\n  }\\n\\n  private buildDeliverables(analysis: RequestAnalysis): Deliverable[] {\\n    const deliverables: Deliverable[] = analysis.targets.map((target) => ({\\n      description: `${analysis.category === \\\"scaffold\\\" ? \\\"Create\\\" : \\\"Modify\\\"} ${target}`,\\n      targetFiles: [target],\\n      type: analysis.category === \\\"scaffold\\\" ? \\\"create\\\" as const : \\\"modify\\\" as const,\\n    }));\\n\\n    // Auto-add test deliverable if configured\\n    if (\\n      this.config.autoTestDeliverables &&\\n      analysis.category !== \\\"test\\\" &&\\n      analysis.category !== \\\"docs\\\" &&\\n      analysis.category !== \\\"investigation\\\"\\n    ) {\\n      deliverables.push({\\n        description: \\\"Add or update tests for changed code\\\",\\n        targetFiles: analysis.targets.map((t) =>\\n          t.replace(/\\\\.(ts|tsx)$/, \\\".test.$1\\\")\\n        ),\\n        type: \\\"create\\\",\\n      });\\n    }\\n\\n    // If no targets extracted, create a placeholder deliverable\\n    if (deliverables.length === 0) {\\n      deliverables.push({\\n        description: analysis.raw,\\n        targetFiles: [],\\n        type: analysis.category === \\\"scaffold\\\" ? \\\"create\\\" : \\\"modify\\\",\\n      });\\n    }\\n\\n    return deliverables;\\n  }\\n\\n  private determineQualityBar(analysis: RequestAnalysis): QualityBar {\\n    if (analysis.riskSignals.includes(\\\"security-sensitive\\\")) return \\\"hardened\\\";\\n    if (analysis.riskSignals.includes(\\\"production-facing\\\")) return \\\"hardened\\\";\\n    if (analysis.scopeEstimate === \\\"trivial\\\") return \\\"minimal\\\";\\n    return this.config.defaultQualityBar;\\n  }\\n}\\n\\n// ─── Errors ──────────────────────────────────────────────────────────\\n\\nexport class CharterScopeError extends Error {\\n  constructor(message: string) {\\n    super(message);\\n    this.name = \\\"CharterScopeError\\\";\\n  }\\n}\\n\",\"lineCount\":286}],\"summaries\":[{\"imports\":[\"node:fs/promises\",\"./file-lock.js\",\"node:path\"],\"exports\":[\"TaskSummary\",\"FileCluster\",\"ProjectMemory\",\"TaskPatternProfile\",\"deriveTaskTypeKey\",\"findPatternWarnings\",\"HistoricalInsight\",\"findHistoricalInsights\",\"getConfidenceDampening\",\"shouldRecommendStrictMode\",\"getReliabilityTier\",\"loadMemory\",\"saveMemory\",\"recordTask\",\"clearMemory\",\"deleteMemory\",\"getMemoryFilePath\"],\"functions\":[\"memoryPath\",\"fileExists\",\"detectLanguage\",\"emptyMemory\",\"isTaskSummary\",\"isFileCluster\",\"normalizeTouchedFiles\",\"isTaskPatternProfile\",\"normalizeList\",\"deriveTaskTypeKey\",\"computeReliabilityTier\",\"computeConfidenceDampening\",\"updateTaskPatterns\",\"isOverconfident\",\"findPatternWarnings\",\"findHistoricalInsights\",\"getConfidenceDampening\",\"shouldRecommendStrictMode\",\"getReliabilityTier\",\"updateFileClusters\",\"loadMemory\",\"saveMemory\",\"recordTask\",\"acquire\",\"clearMemory\",\"deleteMemory\",\"getMemoryFilePath\"],\"classes\":[],\"patterns\":[\"imports\",\"exports\",\"test-file\"],\"summary\":\"3 imports; 17 exports; 27 functions; patterns imports, exports, test-file\"},{\"imports\":[\"./project-memory.js\",\"./change-set.js\",\"./multi-file-planner.js\",\"./invariant-extractor.js\"],\"exports\":[\"GatedContext\",\"WaveInvariantRef\",\"gateContext\",\"WaveContextInputs\",\"gateContextForWave\",\"gateContextForArchitectural\",\"mergeGatedContext\"],\"functions\":[\"gateContext\",\"gateContextForWave\",\"gateContextForArchitectural\",\"mergeGatedContext\",\"extractPromptWords\",\"uniqu